INSERT INTO `posts` (`id_post`, `id_category`, `title`, `synopsis`, `content`, `main_image`, `created_at`, `id_user`, `orden`, `instructor_name`, `instructor_title`, `instructor_photo`, `show_in_instructors`) VALUES
(52, 16, 'Técnico en Auxiliar en Veterinaria', 'El programa otorga las competencias necesarias para dar apoyo al médico veterinario en procedimientos médicos y quirúrgicos.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">El programa pretende formar estudiantes capaces de dar apoyo al m&eacute;dico veterinario en procedimientos m&eacute;dicos y quir&uacute;rgicos.&nbsp; Adem&aacute;s conocer los fundamentos de los cuidados de animales de compa&ntilde;&iacute;a y su comportamiento, atenci&oacute;n durante la consulta e internamiento en animales con alguna patolog&iacute;a.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Conocimientos para cuidar las mascotas,&nbsp;nutrici&oacute;n animal, sistema de alimentaci&oacute;n y&nbsp;alternativas.</li>\r\n<li>Habilidad para realizar un examen cl&iacute;nico.</li>\r\n<li>Manejo de situaciones como las&nbsp;enfermedades parasitarias e infecciones.</li>\r\n<li>Primeros auxilios y atenci&oacute;n de&nbsp;emergencias sencillas.</li>\r\n<li>Participaci&oacute;n en talleres y visitas de&nbsp;campo para poner en pr&aacute;ctica los&nbsp;conocimientos adquiridos.</li>\r\n<li>Competencia para emprender en un&nbsp;negocio.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como Auxiliar en Farmacia.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69a6134fbc32d4.48574354-Veterinaria.png', '2026-02-28 17:37:40', 7, 0, '', '', '', 0),
(53, 16, 'Técnico en Auxiliar en Farmacia', 'El programa Otorga las competencias necesarias para dar soporte al Farmacéutico y cumplir con las operaciones que se desarrollan en una farmacia comunitaria.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">Adquirir&aacute;s conocimientos farmacol&oacute;gicos de los diferentes productos; podr&aacute;s asesorar con eficiencia a los clientes de acuerdo a sus necesidades. Adem&aacute;s de obtener conocimientos de despacho y almacenaje de las medicinas.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Atenci&oacute;n al cliente enfocada en&nbsp;medicamentos.</li>\r\n<li>Colaboraci&oacute;n en el manejo de&nbsp;inventario de la farmacia.</li>\r\n<li>Soporte al farmac&eacute;utico en el&nbsp;despacho de medicamentos.</li>\r\n<li>Promover el uso racional de los&nbsp;medicamentos.</li>\r\n<li>Adquirir la terminolog&iacute;a necesaria&nbsp;para trabajar en una Farmacia.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como Auxiliar en Farmacia.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69a612b8a1e294.57788061-Farmacia.png', '2026-02-28 17:50:20', 7, 0, '', '', '', 0),
(54, 16, 'Técnico en Red de Cuido y Asistente de Pacientes', 'Adquiere conocimientos, habilidades y destrezas que te permita brindar una atención integral del paciente que lo necesite.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">Otorga las competencias y habilidades id&oacute;neas para que el participante pueda formarse para un acompa&ntilde;amiento integral del&nbsp; paciente. Desarrolla conocimientos, habilidades y destrezas que&nbsp;les permitan brindar una&nbsp;Atenci&oacute;n Integral de Pacientes&nbsp;en el lugar que &eacute;stos se&nbsp;encuentren, con&nbsp;conocimientos en varios&nbsp;campos relacionados con esta&nbsp;actividad y que mejoren la&nbsp;calidad de vida, atenci&oacute;n y&nbsp;confort.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li><strong>Atenci&oacute;n integral al paciente:</strong> Brindar asistencia personalizada a pacientes en hospitales, cl&iacute;nicas, hogares de cuidado&nbsp;y entornos domiciliarios.&nbsp;Respetar la dignidad, privacidad y derechos del paciente en todas las interacciones.</li>\r\n<li><strong>Conocimientos b&aacute;sicos en salud:</strong>&nbsp;Reconocer signos vitales (presi&oacute;n arterial, frecuencia card&iacute;aca, temperatura, saturaci&oacute;n&nbsp;de ox&iacute;geno, entre otros) y reportar anomal&iacute;as al personal m&eacute;dico.&nbsp;Aplicar conocimientos b&aacute;sicos en anatom&iacute;a, fisiolog&iacute;a, primeros auxilios y control de&nbsp;infecciones.</li>\r\n<li><strong>Habilidades pr&aacute;cticas:</strong>&nbsp;Ayudar en la movilizaci&oacute;n, higiene personal y alimentaci&oacute;n.&nbsp;Manejar equipos b&aacute;sicos como gluc&oacute;metros, tensi&oacute;metros y term&oacute;metros.</li>\r\n<li><strong>Soporte emocional:&nbsp;</strong>Proporcionar apoyo emocional al paciente y su familia en situaciones de enfermedad&nbsp;o recuperaci&oacute;n.&nbsp;Facilitar la comunicaci&oacute;n entre el paciente, sus familiares y el equipo de salud.</li>\r\n<li><strong>&Eacute;tica y responsabilidad profesional:</strong>&nbsp;Actuar con profesionalismo, condencialidad y &eacute;tica en el manejo de informaci&oacute;n del&nbsp;paciente.&nbsp;Mostrar empat&iacute;a, paciencia y sensibilidad en el cuidado de personas vulnerables.</li>\r\n<li><strong>Trabajo en equipo:</strong>&nbsp;Colaborar con el equipo interdisciplinario de salud para garantizar la atenci&oacute;n integral&nbsp;del paciente.&nbsp;Participar en la elaboraci&oacute;n y seguimiento de planes de cuidado, seg&uacute;n las indicaciones&nbsp;m&eacute;dicas o de enfermer&iacute;a.</li>\r\n</ul>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte en Red de Cuido y Asistente de Pacientes.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69a60ef69e3c34.20202171-Red de cuido.png', '2026-02-28 17:59:20', 7, 0, '', '', '', 0),
(55, 16, 'Técnico en  Asistente Dental', 'El programa le brinda al participante las habilidades necesarias para asistir de forma efectiva a los profesionales de la salud en sus labores administrativas y complementarias del ambiente de la clínica.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">El programa proporciona al estudiante aspectos generales de la odontolog&iacute;a y sus diferentes especialidades como la ortodoncia, as&iacute; mismo conoce generalidades y procedimientos relacionados con esta &aacute;rea de la salud. Este programa le brinda al participante las habilidades necesarias para asistir de forma efectiva a los profesionales de la salud en sus labores administrativas y complementarias del ambiente de la cl&iacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Identificar aspectos generales de la odontolog&iacute;a, especialidades y procedimientos b&aacute;sicos.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Diferenciar las especialidades, ramas y&nbsp;procedimientos que se llevan en el &aacute;rea de la&nbsp;odontolog&iacute;a.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Distinguir aspectos propios del&nbsp;ambiente de la cl&iacute;nica, procedimientos&nbsp;administrativos, servicio al cliente, control y&nbsp;seguimiento.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como Asistente Dental.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n<li>Taller pr&aacute;cticos.&nbsp;</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>\r\n<p>&nbsp;</p>', 'post_69a60ee25067a3.78209934-Dental.png', '2026-02-28 18:58:51', 7, 0, '', '', '', 0),
(56, 24, 'Diplomado en Asistencia Veterinaria', 'Desarrolla conocimientos científicos y habilidades prácticas, comprometidos con la salud y el bienestar animal, la salud pública y la productividad agropecuaria.', '<h4><big><strong>Descripci&oacute;n&nbsp;</strong></big></h4>\r\n<p><big>Tiene como objetivo formar tecn&oacute;logos especializados en Asistencia Veterinaria, mediante la ejecuci&oacute;n de actividades pr&aacute;cticas basadas en principios cient&iacute;ficos y orientadas al compromiso &eacute;tico y la equidad social, con el prop&oacute;sito de contribuir al desarrollo de las ciencias veterinarias, promover la&nbsp;salud animal, proteger la&nbsp;salud p&uacute;blica y fortalecer la&nbsp;productividad pecuaria,&nbsp;mejorando as&iacute; las&nbsp;condiciones</big></p>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<h4><big><strong>Duraci&oacute;n del Programa</strong></big></h4>\r\n<p><big>2 a&ntilde;os, divididos en 6 cuatrimestres.</big></p>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<h4><big><strong>Conocimientos a adquirir&nbsp;</strong></big></h4>\r\n<ul>\r\n<li>Comprender la importancia de garantizar un manejo&nbsp;integral y adecuado de la salud animal mediante de la&nbsp;ejecuci&oacute;n de actividades pr&aacute;cticas fundamentadas en&nbsp;principios cient&iacute;ficos, que incluyen t&eacute;cnicas de manipulaci&oacute;n,&nbsp;diagn&oacute;stico, tratamiento y prevenci&oacute;n en diferentes especies&nbsp;animales, bajo un enfoque &eacute;tico y de compromiso social,&nbsp;para &eacute;l apoya eficaz al m&eacute;dico veterinario en cl&iacute;nicas,&nbsp;granjas y laboratorios.</li>\r\n<li>Contribuir a la mejora de las condiciones de vida de los animales, la protecci&oacute;n de la salud p&uacute;blica y el aumento de la productividad pecuaria a trav&eacute;s de la asistencia veterinaria en la aplicaci&oacute;n de t&eacute;cnicas veterinarias y practicas sustentadas en los principios cient&iacute;ficos.</li>\r\n<li>Desarrollar conocimientos, habilidades, destrezas t&eacute;cnicas para la ejecuci&oacute;n de las actividades cl&iacute;nicas, granjas, laboratorios y otros ambientes relacionados con la salud animal mediante la supervisi&oacute;n del m&eacute;dico veterinario.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<h4><big><strong><strong id=\"docs-internal-guid-dc2fed11-7fff-ef86-545e-443e17388ecf\">Perfil Profesional</strong></strong></big></h4>\r\n<p class=\"MsoListParagraph\" style=\"text-indent: -0.25in; padding-left: 40px;\"><!-- [if !supportLists]--><span lang=\"ES-TRAD\" style=\"mso-ansi-language: ES-TRAD;\">El Diplomado en Asistencia Veterinaria es un profesional comprometido con el mejoramiento de la calidad de vida y el desarrollo humano sustentable, que posee un esp&iacute;ritu &eacute;tico, cient&iacute;fico y humanista. Est&aacute; capacitado para ejecutar acciones orientadas a la prevenci&oacute;n, planificaci&oacute;n y soluci&oacute;n de problem&aacute;ticas en diversos &aacute;mbitos relacionados con la producci&oacute;n animal, el medio ambiente y todo lo vinculado directa o indirectamente con las especies animales. Adem&aacute;s, cuenta con una formaci&oacute;n s&oacute;lida que le permite continuar su desarrollo acad&eacute;mico en niveles de Educaci&oacute;n Superior.</span></p>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<h4><big><strong id=\"docs-internal-guid-dc2fed11-7fff-ef86-545e-443e17388ecf\">Perfil Ocupacional</strong></big></h4>\r\n<p style=\"margin: 0in; line-height: 150%;\"><span lang=\"ES-TRAD\" style=\"font-family: \'Arial\',sans-serif; mso-fareast-font-family: Calibri; mso-fareast-theme-font: minor-latin; mso-ansi-language: ES-TRAD; mso-fareast-language: EN-US;\">El graduado del diplomado en asistencia veterinaria podr&aacute; incursionar en empresas y/o sectores de las siguientes categor&iacute;as:</span></p>\r\n<ul>\r\n<li style=\"line-height: 150%;\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Centros m&eacute;dico-quir&uacute;rgicos de animales dom&eacute;sticos (hospitales de medicina veterinaria en especies mayores y menores).</span></li>\r\n<li style=\"line-height: 150%;\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Laboratorios de diagn&oacute;stico veterinario: patolog&iacute;a, microbiolog&iacute;a, parasitolog&iacute;a.</span></li>\r\n<li style=\"line-height: 150%;\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Industrias de producci&oacute;n pecuaria: bovina de carne, bovina lechera, carnes, av&iacute;cola, porcina y otras.</span></li>\r\n<li style=\"line-height: 150%;\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Salud ambiental, entre otras.</span></li>\r\n<li style=\"line-height: 150%;\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Medicina veterinaria preventiva.</span></li>\r\n<li style=\"line-height: 150%;\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Salud p&uacute;blica veterinaria.</span></li>\r\n<li style=\"line-height: 150%;\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Salud y producci&oacute;n animal.</span></li>\r\n<li style=\"line-height: 150%;\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Centros de diagn&oacute;stico por im&aacute;genes y ultrasonidos en medicina veterinaria.</span></li>\r\n<li style=\"line-height: 150%;\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Hoteler&iacute;a veterinario.</span></li>\r\n<li style=\"line-height: 150%;\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Asistente en campo de la m&eacute;dico veterinaria.</span></li>\r\n<li style=\"line-height: 150%;\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Vida silvestre, zool&oacute;gicos y centros de rehabilitaci&oacute;n de animales silvestres.</span></li>\r\n<li style=\"line-height: 150%;\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Econom&iacute;a y administraci&oacute;n de empresas pecuarias.</span></li>\r\n<li style=\"line-height: 150%;\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Asistente en investigaci&oacute;n, docencia universitaria y t&eacute;cnico-profesional.</span></li>\r\n<li style=\"line-height: 150%;\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Etolog&iacute;a en las diferentes especies (comportamiento animal).</span></li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<h3><big><strong>Modalidad</strong></big></h3>\r\n<p>&nbsp;</p>\r\n<ul>\r\n<li>\r\n<p><big><strong>Presencial,&nbsp;</strong>en las instalaciones CEFI en Valle del Sol, Gu&aacute;piles</big></p>\r\n</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<h3><big><strong>Requisitos</strong></big></h3>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: 0in;\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Para ingresar a este Diplomado se requiere:</span></p>\r\n<ul>\r\n<li class=\"MsoNormal\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Poseer el T&iacute;tulo de Bachillerato en Educaci&oacute;n Media o su equivalente debidamente reconocido.</span></li>\r\n<li class=\"MsoNormal\"><!-- [if !supportLists]--><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Presentar dos copias del T&iacute;tulo de Bachillerato en Educaci&oacute;n Media o su equivalente debidamente reconocido.</span></li>\r\n<li class=\"MsoNormal\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">T&eacute;cnicos medios egresados de colegios t&eacute;cnicos.</span></li>\r\n<li class=\"MsoNormal\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Diplomados de carreras afines.</span></li>\r\n<li class=\"MsoNormal\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Cumplir con los requisitos administrativos.</span></li>\r\n</ul>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: 0in;\"><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">&nbsp;</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: 0in;\"><em><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\"><strong>Para los estudiantes extranjeros:</strong> </span><span lang=\"ES-TRAD\" style=\"mso-bidi-font-size: 12.0pt; line-height: 150%; mso-bidi-font-family: Arial; mso-ansi-language: ES-TRAD;\">Presentar el titulo original de conclusi&oacute;n de estudios secundarios autenticado por las autoridades consulares de Costa Rica en el pa&iacute;s de emisi&oacute;n y por el Ministerio de Educaci&oacute;n P&uacute;blica de Costa Rica, seg&uacute;n las leyes y normativas del Gobierno de la Rep&uacute;blica de Costa Rica.</span></em></p>', 'post_69a7488922aae3.65481239-Diplomado en Asistencia Veterinaria.png', '2026-03-02 21:10:57', 6, 0, '', '', '', 0),
(58, 14, 'Técnico en Secretariado Ejecutivo', 'Capacitar al estudiante en aspectos técnicos-prácticos para formar profesionales en el campo secretarial.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">Preparar al ejecutivo para que desarrolle todo su potencial administrativo, de organizaci&oacute;n y ejecuci&oacute;n de funciones, de modo que se convierta en el verdadero valor agregado que la empresa o entidad brinde tanto a sus colaboradores internos como externos.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<p>El profesional en secretariado ejecutivo es una&nbsp;de las profesiones m&aacute;s importante actualmente&nbsp;pues desarrolla el personal m&aacute;s capacitado para&nbsp;realizar tareas administrativas que organicen y&nbsp;apoyen las funciones ejecutivas de la empresa.&nbsp;Los temas desarrollados en este curso permiten&nbsp;que el estudiante logre un desarrollo personal,&nbsp;social y econ&oacute;mico aportando un valor agregado&nbsp;para la vida en igualdad de oportunidades y de&nbsp;acceso, sin distingo de genero.</p>\r\n<ul>\r\n<li>Desarrollar capacidades para poder&nbsp;atender aspectos relacionados con la&nbsp;atenci&oacute;n de clientes externos e internos de&nbsp;la empresa o instituci&oacute;n.</li>\r\n<li>Que el estudiante obtenga las destrezas necesarias en el uso de herramientas Microsoft Office para manejar la informaci&oacute;n requerida.</li>\r\n<li>Adiestrar en el uso de t&eacute;cnicas de organizaci&oacute;n y administraci&oacute;n de documentos y de cada una de las tareas de oficina.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico en Secretariado Ejecutivo.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial y/o virtual.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li><strong>Virtual</strong>, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">Computadora.</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69a899450aaeb4.67272351-Secretariado.png', '2026-03-03 06:33:18', 7, 0, '', '', '', 0),
(59, 14, 'Técnico en Preescolar', 'El programa permite desarrollar lo necesario para la contribución del desarrollo físico, intelectual,\r\nafectivo y moral de los niños.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">El programa promueve la adquisici&oacute;n de conocimientos te&oacute;ricos pr&aacute;cticos para trabajar con estudiantes de 0 a 8 a&ntilde;os. Brinda el conocimiento necesario en herramientas did&aacute;cticas para la labor docente en ni&ntilde;os y ni&ntilde;as de edad preescolar, adem&aacute;s se fortalece el conocimiento te&oacute;rico para comprender los diversos estilos de aprendizajes que se puedan presentar en el desarrollo de ni&ntilde;os y ni&ntilde;as.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Dirigido a&nbsp;</h2>\r\n<p>El programa t&eacute;cnico en preescolar se dirige a personas que:</p>\r\n<ul>\r\n<li>Tengan deseos de adquirir conocimientos te&oacute;ricos pr&aacute;cticos para el trabajo&nbsp;con ni&ntilde;os y ni&ntilde;as en edad de 0 a 8 a&ntilde;os.</li>\r\n<li>Que disfruten el trabajo con ni&ntilde;os y ni&ntilde;as en edad de 0 a 8 a&ntilde;os.</li>\r\n<li>Que sean emp&aacute;ticas y responsables con ni&ntilde;os y ni&ntilde;as en edad de 0 a 8&nbsp;a&ntilde;os.</li>\r\n<li>Que deseen desarrollar habilidades y destrezas para trabajar con ni&ntilde;os y&nbsp;ni&ntilde;as en la etapa de desarrollo entre las edades de 0 a 8 a&ntilde;os.</li>\r\n<li>Que deseen trabajar por el bienestar integral de los ni&ntilde;os y ni&ntilde;as de edad&nbsp;preescolar.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico en Preescolar.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69a89951149176.43414495-Preescolar.png', '2026-03-03 06:37:56', 7, 0, '', '', '', 0),
(60, 14, 'Técnico en Asistente Judicial y Legal', 'El programa otorga los conocimientos teóricos y prácticos para asistir y auxiliar de manera eficiente al abogado en su labor, permitiendo colaborar en forma activa y responsable con los profesionales del derecho.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">Dota a los participantes de los conocimientos fundamentales que todo asistente jur&iacute;dico debe manejar en relaci&oacute;n con el l&eacute;xico&nbsp; jur&iacute;dico, la investigaci&oacute;n, as&iacute; como la elaboraci&oacute;n de documentos y tramitaci&oacute;n de documentos jur&iacute;dicos, a efectos de facilitar su inserci&oacute;n en despacho legales o instituciones p&uacute;blicas en calidad de asistente o auxiliar jur&iacute;dico de las y los abogados.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Manejar un amplio vocabulario&nbsp;jur&iacute;dico para expresarse con&nbsp;propiedad y comprender las&nbsp;instrucciones que se le giren.</li>\r\n<li>Conocer las fuentes y los m&eacute;todos&nbsp;de investigaci&oacute;n jur&iacute;dica usuales para&nbsp;generar insumos para informes y&nbsp;consultor&iacute;a.</li>\r\n<li>Elaboraci&oacute;n de diferentes&nbsp;documentos legales para apoyar al&nbsp;abogado en su gesti&oacute;n.</li>\r\n<li>Adquirir un conocimiento general&nbsp;respecto de los distintos &oacute;rganos y&nbsp;entes p&uacute;blicos a efectos de solicitar&nbsp;informaci&oacute;n o presentar gestiones.</li>\r\n</ul>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico en Asistente Judicial y Legal.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial y/o virtual.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li><strong>Virtual</strong>, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69a8996012e3e0.92898579-Judicial.png', '2026-03-03 06:43:35', 7, 0, '', '', '', 0);
INSERT INTO `posts` (`id_post`, `id_category`, `title`, `synopsis`, `content`, `main_image`, `created_at`, `id_user`, `orden`, `instructor_name`, `instructor_title`, `instructor_photo`, `show_in_instructors`) VALUES
(61, 14, 'Técnico en Diseño Gráfico con IA', 'Desarrolla en el estudiante las competencias esenciales y avanzadas del diseño digital, abarcando retoque fotográfico, creación vectorial, maquetación profesional y el uso estratégico de herramientas de inteligencia artificial.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p>El programa combina formaci&oacute;n t&eacute;cnica, creativa y tecnol&oacute;gica para preparar a los nuevos dise&ntilde;adores digitales en un entorno&nbsp; moderno y competitivo. A lo largo de tres m&oacute;dulos progresivos, el estudiante aprender&aacute; desde los fundamentos del dise&ntilde;o fotogr&aacute;fico y vectorial, hasta t&eacute;cnicas avanzadas de composici&oacute;n, automatizaci&oacute;n de procesos, creaci&oacute;n de contenido corporativo y desarrollo de proyectos completos. El curso incluye el uso de plataformas l&iacute;deres como Photoshop, Illustrator, Figma y Affnity, adem&aacute;s de la integraci&oacute;n de herramientas de inteligencia artificial como ChatGPT, Perplexity, Gemini y Qwen, aplicadas al dise&ntilde;o, creaci&oacute;n de contenido, generaci&oacute;n de im&aacute;genes, prototipado y automatizaci&oacute;n.</p>\r\n<p>Al finalizar, el alumno ser&aacute; capaz de crear proyectos visuales completos, integrando procesos creativos, t&eacute;cnicos y automatizados para responder a las necesidades del entorno profesional actual.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<p>Al finalizar este programa, el estudiante contar&aacute; con:</p>\r\n<ul>\r\n<li>Habilidades T&eacute;cnicas y Creativas</li>\r\n<li>Dominio de herramientas de retoque fotogr&aacute;fico&nbsp;b&aacute;sico y avanzado.</li>\r\n<li>Creaci&oacute;n de im&aacute;genes, composiciones, filtros,&nbsp;capas y objetos inteligentes.</li>\r\n<li>Conocimiento s&oacute;lido en dise&ntilde;o vectorial, logos,&nbsp;ilustraci&oacute;n y branding corporativo.</li>\r\n<li>Uso profesional de software de dise&ntilde;o:&nbsp;Photoshop, Illustrator, Figma y Affinity.</li>\r\n<li>Competencias en IA Aplicada al Dise&ntilde;o</li>\r\n<li>Uso de ChatGPT como asistente creativo y&nbsp;t&eacute;cnico.</li>\r\n<li>Aplicaci&oacute;n de Perplexity para generaci&oacute;n de&nbsp;contenido visual y conceptual.</li>\r\n<li>Integraci&oacute;n de Gemini como soporte en creaci&oacute;n&nbsp;de aplicaciones y automatizaciones.</li>\r\n<li>Utilizaci&oacute;n de Qwen como herramienta multitarea&nbsp;para flujos de trabajo avanzados.</li>\r\n<li>Dominio de Maquetaci&oacute;n y Creaci&oacute;n de Contenidos</li>\r\n<li>Dise&ntilde;o de revistas, boletines y materiales&nbsp;digitales profesionales.</li>\r\n<li>Desarrollo de proyectos completos para redes&nbsp;sociales y entornos digitales.</li>\r\n<li>Creaci&oacute;n de sistemas gr&aacute;ficos con coherencia&nbsp;visual.</li>\r\n<li><strong>Proyecto Final</strong>:&nbsp;Un proyecto integral que re&uacute;ne dise&ntilde;o&nbsp;fotogr&aacute;fico, vectorial, maquetaci&oacute;n y automatizaci&oacute;n&nbsp;con IA, demostrando todas las habilidades del&nbsp;programa.</li>\r\n</ul>\r\n<p><strong>Desarrollo Profesional:</strong></p>\r\n<ul>\r\n<li>Preparaci&oacute;n para trabajar en estudios de dise&ntilde;o,&nbsp;agencias creativas, marketing digital o&nbsp;emprendimientos personales.</li>\r\n<li>Portafolio completo y funcional con trabajos&nbsp;desarrollados durante los 12 meses.</li>\r\n</ul>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico en Dise&ntilde;o Gr&aacute;fico con IA.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">Computadora.</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69a8996a998928.42985278-Diseño.png', '2026-03-03 06:50:13', 7, 0, '', '', '', 0),
(62, 14, 'Técnico en Contabilidad con énfasis en Control Interno', 'Desarrolla las destrezas y habilidades necesarias para apoyar los procesos contables, así como actividades relacionadas con el control interno.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p>El plan est&aacute; dise&ntilde;ado para que la persona egresada pueda apoyar diversas &aacute;reas vinculadas a la contabilidad, es decir, aquellas actividades propias del ejercicio de esta profesi&oacute;n que actualmente ha evolucionado por los grandes cambios normativos que enmarcan esta ciencia econ&oacute;mica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Desarrollar las destrezas y&nbsp;habilidades necesarias para apoyar los&nbsp;procesos contables, as&iacute; como actividades&nbsp;relacionadas con el control interno.</li>\r\n<li>Estudiar las generalidades de la&nbsp;profesi&oacute;n contable y sus &aacute;reas de acci&oacute;n.</li>\r\n<li>Determinar aquellos elementos&nbsp;esenciales del proceso contable de las&nbsp;organizaciones.</li>\r\n<li>Comprender la importancia de la&nbsp;correcta presentaci&oacute;n de la informaci&oacute;n&nbsp;financiera contable con fines fiscales.</li>\r\n</ul>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico en Contabilidad con &eacute;nfasis en Control Interno.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad virtual y/o presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li><strong>Virtual</strong>, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">Computadora.</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69a89974ea09b3.65441438-Contabilidad.png', '2026-03-03 06:55:02', 7, 0, '', '', '', 0),
(64, 24, 'Diplomado en Producción Agropecuaria', 'Desarrolla competencias para manejar sistemas productivos agropecuarios sostenibles, integrando conocimientos técnicos, administrativos y empresariales para la gestión eficiente de recursos en explotaciones agrícolas y pecuarias', '<hr class=\"my-4\">\r\n<div class=\"post-content\">\r\n<h4><big><strong>Descripci&oacute;n&nbsp;</strong></big></h4>\r\n<p>Desarrollar capacidades en&nbsp;producci&oacute;n agropecuaria con&nbsp;una visi&oacute;n integral y&nbsp;sostenible, orientadas a&nbsp;optimizar los sistemas de&nbsp;producci&oacute;n animal y vegetal&nbsp;mediante la aplicaci&oacute;n de&nbsp;conocimientos, t&eacute;cnicas y&nbsp;tecnolog&iacute;as apropiadas, a&nbsp;trav&eacute;s de una formaci&oacute;n&nbsp;te&oacute;rico pr&aacute;ctica que&nbsp;contribuya a satisfacer las&nbsp;demandas actuales y futuras&nbsp;de alimentos, en armon&iacute;a con&nbsp;el medio ambiente y&nbsp;promoviendo el desarrollo&nbsp;rural.</p>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<h4><big><strong>Duraci&oacute;n del Programa</strong></big></h4>\r\n<p><big>2 a&ntilde;os, divididos en 6 cuatrimestres.</big></p>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<h4><big><strong>Conocimientos a adquirir&nbsp;</strong></big></h4>\r\n<ul>\r\n<li style=\"line-height: 150%;\">Desarrollar conocimientos, habilidades, destrezas las&nbsp;capacidades para mejorar la productividad y sostenibilidad&nbsp;de los sistemas agropecuarios, a trav&eacute;s de la aplicaci&oacute;n de&nbsp;conocimientos cient&iacute;ficos, tecnolog&iacute;as innovadoras y&nbsp;pr&aacute;cticas agropecuarias responsables que respondan a las&nbsp;demandas actuales del sector.</li>\r\n<li style=\"line-height: 150%;\">Implementar herramientas de gesti&oacute;n, planificaci&oacute;n y evaluaci&oacute;n de proyectos agropecuarios, con el fin de promover la rentabilidad y competitividad de las unidades productivas, mediante una formaci&oacute;n te&oacute;rico pr&aacute;ctica que integre aspectos t&eacute;cnicos, administrativos y ambientales.</li>\r\n<li style=\"line-height: 150%;\">Aplicar de manera eficiente las tecnolog&iacute;as de la informaci&oacute;n, la maquinaria agr&iacute;cola y las t&eacute;cnicas de agricultura de precisi&oacute;n, mediante el uso de sistemas digitales y metodolog&iacute;as innovadoras adaptadas a las din&aacute;micas del sector, para optimizar la toma de decisiones y el manejo integral de la producci&oacute;n agropecuaria.</li>\r\n</ul>\r\n<hr>\r\n<h4><big><strong id=\"docs-internal-guid-dc2fed11-7fff-ef86-545e-443e17388ecf\">Perfil Profesional</strong></big></h4>\r\n<p class=\"MsoListParagraph\">El tecn&oacute;logo de este Diplomado es un&nbsp;profesional comprometido con el&nbsp;mejoramiento de la calidad de vida y el&nbsp;desarrollo humano sustentable, que&nbsp;posee un esp&iacute;ritu &eacute;tico, cient&iacute;fico y&nbsp;humanista. Est&aacute; capacitado para&nbsp;ejecutar acciones orientadas a la&nbsp;prevenci&oacute;n, planificaci&oacute;n y soluci&oacute;n de&nbsp;problem&aacute;ticas en diversos &aacute;mbitos&nbsp;relacionados con la producci&oacute;n animal,&nbsp;el medio ambiente y todo lo vinculado&nbsp;directa o indirectamente</p>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<h4><big><strong id=\"docs-internal-guid-dc2fed11-7fff-ef86-545e-443e17388ecf\">Perfil Ocupacional</strong></big></h4>\r\n<p>El graduado del diplomado en Producci&oacute;n Agropecuaria podr&aacute; incursionar en:</p>\r\n<ul>\r\n<li>Asistir en la supervisi&oacute;n de explotaciones agr&iacute;colas y ganaderas, abarcando la planificaci&oacute;n, producci&oacute;n, manejo de cultivos y cuidado de animales.</li>\r\n<li>Asistencia t&eacute;cnica a agricultores y ganaderos para mejorar la productividad, sostenibilidad y&nbsp;rentabilidad de sus fincas.</li>\r\n<li>Trabajo en empresas agroindustriales, participando en procesos de transformaci&oacute;n,&nbsp;comercializaci&oacute;n y control de calidad de productos agropecuarios.</li>\r\n<li>Dise&ntilde;o, formulaci&oacute;n, ejecuci&oacute;n y evaluaci&oacute;n de proyectos productivos agropecuarios, con&nbsp;&eacute;nfasis en sostenibilidad ambiental y uso eficiente de recursos.</li>\r\n<li>Operaci&oacute;n y manejo de tecnolog&iacute;as, maquinaria agr&iacute;cola, incluyendo sistemas de riego,&nbsp;drenaje y agricultura de precisi&oacute;n.</li>\r\n<li>Investigaci&oacute;n, desarrollo e innovaci&oacute;n referente a la producci&oacute;n agropecuaria.</li>\r\n<li>Docencia y capacitaci&oacute;n t&eacute;cnica en instituciones educativas y centros de formaci&oacute;n&nbsp;agropecuaria.</li>\r\n<li>Participaci&oacute;n en organismos p&uacute;blicos, privados o sociales relacionados con la producci&oacute;n&nbsp;agropecuaria.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<h3><big><strong>Modalidad</strong></big></h3>\r\n<ul>\r\n<li>\r\n<p><big><strong>Presencial,&nbsp;</strong>en las instalaciones CEFI en Valle del Sol, Gu&aacute;piles</big></p>\r\n</li>\r\n</ul>\r\n<hr>\r\n<h3><big><strong>Requisitos</strong></big></h3>\r\n<p class=\"MsoNormal\"><span lang=\"ES-TRAD\">Para ingresar a este Diplomado se requiere:</span></p>\r\n<ul>\r\n<li class=\"MsoNormal\"><span lang=\"ES-TRAD\">Poseer el T&iacute;tulo de Bachillerato en Educaci&oacute;n Media o su equivalente debidamente reconocido.</span></li>\r\n<li class=\"MsoNormal\"><span lang=\"ES-TRAD\">Presentar dos copias del T&iacute;tulo de Bachillerato en Educaci&oacute;n Media o su equivalente debidamente reconocido.</span></li>\r\n<li class=\"MsoNormal\"><span lang=\"ES-TRAD\">T&eacute;cnicos medios egresados de colegios t&eacute;cnicos.</span></li>\r\n<li class=\"MsoNormal\"><span lang=\"ES-TRAD\">Diplomados de carreras afines.</span></li>\r\n<li class=\"MsoNormal\"><span lang=\"ES-TRAD\">Cumplir con los requisitos administrativos.</span></li>\r\n</ul>\r\n<p class=\"MsoNormal\"><em><span lang=\"ES-TRAD\"><strong>Para los estudiantes extranjeros:</strong>&nbsp;</span><span lang=\"ES-TRAD\">Presentar el titulo original de conclusi&oacute;n de estudios secundarios autenticado por las autoridades consulares de Costa Rica en el pa&iacute;s de emisi&oacute;n y por el Ministerio de Educaci&oacute;n P&uacute;blica de Costa Rica, seg&uacute;n las leyes y normativas del Gobierno de la Rep&uacute;blica de Costa Rica.</span></em></p>\r\n</div>', 'post_69a74a4d4f7792.23671144-Diplomado en Producción Agropecuaria.png', '2026-03-03 20:53:33', 6, 0, '', '', '', 0),
(65, 18, 'Técnico Especializado en Preparación Física y Entrenamiento Personal', 'Analiza los componentes esenciales del acondicionamiento y ejecución del ejercicio.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">Este t&eacute;cnico consta de 12 cursos que le proporcionan al estudiante aspectos generales el&nbsp;acondicionamiento f&iacute;sico, como medio para desarrollar las capacidades y obtener mayores rendimientos&nbsp;de la ejecuci&oacute;n del ejercicio y la actividad f&iacute;sica. Al mismo tiempo le proporciona aspectos t&eacute;cnicos&nbsp;relevantes para el desarrollo de planes de entrenamiento.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 3 horas de clase por semana sincr&oacute;nica, y&nbsp; 3 horas de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Identificar aspectos generales de la&nbsp;anatom&iacute;a, biomec&aacute;nica y la ejecuci&oacute;n&nbsp;correcta de los ejercicios.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Diferenciar las disciplinas, formas de&nbsp;entrenamiento y aspectos nutricionales&nbsp;que inciden en el acondicionamiento&nbsp;f&iacute;sico.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Distinguir aspectos estrat&eacute;gicos para&nbsp;el desarrollo de diversas oportunidades&nbsp;como personal trainer.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico Especializado en Preparaci&oacute;n F&iacute;sica y Entrenamiento Personal.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n<li>Pr&aacute;cticas y taller en gimnasios.&nbsp;</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>\r\n<p>&nbsp;</p>', 'post_69a75b355bf1e2.36725389-Entrenamiento.png', '2026-03-03 22:05:41', 6, 0, '', '', '', 0),
(66, 14, 'Técnico en Administración de Empresas con énfasis en Desarrollo de Negocios y Finanzas', 'Forma profesionales capaces de planear, organizar, dirigir y controlar múltiples proyectos empresariales.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p>El programa tiene como objetivo otorgar los conocimientos requeridos en el desarrollo de la capacidad anal&iacute;tica y toma de decisiones a nivel empresarial.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Formar profesionales capaces de&nbsp;planear, organizar, dirigir y controlar&nbsp;m&uacute;ltiples proyectos empresariales.</li>\r\n<li>Brindar los conocimientos primordiales&nbsp;de las Ciencias Empresariales, que&nbsp;permitan al estudiante desarrollar&nbsp;habilidades y destrezas en la toma de&nbsp;decisiones gerenciales.</li>\r\n<li>Formar profesionales capaces de&nbsp;entender el fen&oacute;meno organizacional.</li>\r\n<li>Desarrollar modelos empresariales que&nbsp;fomenten el crecimiento y desarrollo&nbsp;financiero.</li>\r\n<li>Toma de decisiones equilibradas y&nbsp;eficientes.</li>\r\n<li>Habilidad en la supervisi&oacute;n de&nbsp;personal.</li>\r\n<li>Habilidad para potenciar los equipos de&nbsp;trabajo.</li>\r\n<li>Habilidad de comunicaci&oacute;n oral y&nbsp;escrita asertiva.</li>\r\n<li>Capacidad anal&iacute;tica para la resoluci&oacute;n&nbsp;de conflictos.</li>\r\n<li>Capacidad para formar nuevas&nbsp;empresas.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico en Administraci&oacute;n de Empresas con &eacute;nfasis en Desarrollo de Negocios y Finanzas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad virtual y/o presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li><strong>Virtual</strong>, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">Computadora.</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69a9f7dc435aa6.62541590-Administración.png', '2026-03-04 23:14:48', 7, 0, '', '', '', 0),
(67, 14, 'Técnico en Seguridad y Salud Ocupacional', 'Desarrolla las destrezas y habilidades necesarias para apoyar los procesos de seguridad y salud ocupacional dentro de las organizaciones. ', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p>El plan est&aacute; dise&ntilde;ado para que la persona egresada pueda apoyar temas operativos propios de la seguridad en los lugares de trabajo y ambientes empresariales, para el resguardo de los colaboradores y su funci&oacute;n dentro de cada una de ellas.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Evaluar y realizar reportes de accidentes laborales.</li>\r\n<li>Determinar requerimientos de sistemas de prevenci&oacute;n de riesgos.</li>\r\n<li>Implementar estrategias tendientes a promover la salud ocupacional en la organizaci&oacute;n.</li>\r\n<li>Velar por el cumplimiento de la legislaci&oacute;n vigente en materia de salud ocupacional.</li>\r\n<li>Aplicar normas nacionales e internacionales para la gesti&oacute;n preventiva de riesgos laborales.</li>\r\n</ul>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico en Seguridad y Salud Ocupacional.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad virtual y/o presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li><strong>Virtual</strong>, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69a9f7fc9250a1.34581003-Seguridad y Salud Ocupacional.png', '2026-03-04 23:17:55', 7, 0, '', '', '', 0),
(68, 14, 'Técnico en Gestión del Talento Humano', 'Desarrolla las habilidades y destrezas para efectuar el óptimo desempeño de los colaboradores que integran\r\nuna organización.', '<p>Tiene como objetivo desarrollar estudios formales sobre los procesos y gesti&oacute;n de la organizaci&oacute;n en sus diferentes niveles.</p>\r\n<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p>Tiene como objetivo el desarrollo de las habilidades y&nbsp;destrezas para efectuar el&nbsp;&oacute;ptimo desempe&ntilde;o de los&nbsp;colaboradores que integran&nbsp;una organizaci&oacute;n.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Dise&ntilde;ar, implementar y administrar los procesos de Gesti&oacute;n del Talento Humano (Planificaci&oacute;n, Formaci&oacute;n y Desarrollo, Reclutamiento y Selecci&oacute;n, Compensaci&oacute;n y beneficios, an&aacute;lisis de puestos, evaluaci&oacute;n del desempe&ntilde;o, entre otros).</li>\r\n<li>Intervenir sobre procesos organizacionales&nbsp;empleando metodolog&iacute;as de trabajo actualizadas.</li>\r\n<li>Dirigir las actividades de Recursos Humanos en el marco de la Ley: C&oacute;digo de Trabajo, Reglamento&nbsp;Interno, C&oacute;digo de &Eacute;tica y dem&aacute;s disposiciones legales de acuerdo al sector de ejercicio.</li>\r\n</ul>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico en Gesti&oacute;n del Talento Humano.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad virtual y/o presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li><strong>Virtual</strong>, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69a9f80b782ee5.77859460-Gestión del Talento Humano.png', '2026-03-04 23:22:02', 7, 0, '', '', '', 0),
(69, 14, 'Técnico en Coach de Salud y Bienestar', 'Forma profesionales capacitados en el área del coaching de salud y bienestar, con conocimientos sólidos en estrategias de cambio de comportamiento, salud integral y técnicas de coaching.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p>Este programa de formaci&oacute;n est&aacute; dise&ntilde;ado para preparar a los futuros t&eacute;cnicos en coaching de salud y bienestar, proporcionando una base s&oacute;lida en principios hol&iacute;sticos de salud, herramientas de coaching y estrategias basadas en la ciencia del comportamiento. El curso&nbsp;se enfoca en el desarrollo de habilidades para ayudar a individuos a alcanzar sus metas de bienestar f&iacute;sico, emocional y mental a trav&eacute;s de cambios sostenibles en su estilo de vida.<br>El coaching de salud y bienestar es una disciplina que combina principios de la salud integral con t&eacute;cnicas de coaching motivacional para ayudar a las personas a mejorar su calidad de vida.</p>\r\n<p>Tiene como objetivo desarrollar estudios formales sobre los procesos y gesti&oacute;n de la organizaci&oacute;n en sus diferentes niveles.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Desarrollar competencias en el uso de herramientas y t&eacute;cnicas de coaching efectivas, que&nbsp;permitan a los futuros profesionales aplicar procesos de comunicaci&oacute;n motivacional,&nbsp;establecimiento de metas y resoluci&oacute;n de obst&aacute;culos fomentando cambios de comportamiento&nbsp;positivo en sus clientes.</li>\r\n<li>Capacitar a los participantes en la evaluaci&oacute;n y dise&ntilde;o de programas personalizados de&nbsp;salud y bienestar, integrando principios de nutrici&oacute;n, ejercicio, manejo del estr&eacute;s y bienestar&nbsp;emocional, adaptados a las necesidades y objetivos espec&iacute;ficos de cada individuo.</li>\r\n<li>Promover una formaci&oacute;n &eacute;tica y profesional en el &aacute;mbito del coaching de salud, asegurando&nbsp;que los participantes comprendan y apliquen los principios de confidencialidad, respeto por la&nbsp;autonom&iacute;a del cliente y responsabilidad en la pr&aacute;ctica profesional del coaching.</li>\r\n</ul>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico en Coach de Salud y Bienestar.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad virtual y/o presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li><strong>Virtual</strong>, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69a9f0044b7455.24974158-Coach de Salud y Bienestar.png', '2026-03-04 23:28:23', 7, 0, '', '', '', 0),
(70, 14, 'Técnico en Portugués', 'Aprende elementos propios de la lengua portuguesa para la aplicación en diferentes ambientes cotidianos y laborales.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p>Este programa est&aacute; organizado en tres niveles, donde la persona participante podr&aacute; conocer desde aspectos culturales hasta mantener conversaciones de uso cotidiano con la fon&eacute;tica precisa y gram&aacute;tica correcta.</p>\r\n<p>Analizar elementos propios&nbsp;de la lengua portuguesa&nbsp;para la aplicaci&oacute;n en&nbsp;diferentes ambientes&nbsp;cotidianos y laborales.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Identificar aspectos generales de la&nbsp;cultura, vocabulario cotidiano y&nbsp;caracter&iacute;sticas de la lengua&nbsp;portuguesa para la contextualizaci&oacute;n&nbsp;de este idioma.</li>\r\n<li>Diferenciar elementos propios de la&nbsp;forma en que se habla en Brasil y&nbsp;Portugal.</li>\r\n<li>Distinguir aspectos fon&eacute;ticos y&nbsp;gramaticales de mayor importancia&nbsp;para el dominio de la lengua.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar manejar el idioma.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad virtual y/o presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li><strong>Virtual</strong>, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69a9efec8480b9.85579303-Portugues.png', '2026-03-04 23:37:22', 7, 0, '', '', '', 0);
INSERT INTO `posts` (`id_post`, `id_category`, `title`, `synopsis`, `content`, `main_image`, `created_at`, `id_user`, `orden`, `instructor_name`, `instructor_title`, `instructor_photo`, `show_in_instructors`) VALUES
(71, 18, 'Técnico Especializado en Electrónica, Automatización y Control de Procesos', 'Proporciona a los estudiantes una formación integral y actualizada en el campo de la electrónica, preparándolos para comprender, diseñar, implementar y mantener sistemas electrónicos.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">El programa de T&eacute;cnico Especializado en Electr&oacute;nica Automatizaci&oacute;n y Control de Procesos proporciona a los estudiantes una formaci&oacute;n integral y&nbsp;actualizada en el campo de la electr&oacute;nica, prepar&aacute;ndolos para comprender, dise&ntilde;ar, implementar y mantener sistemas electr&oacute;nicos. Adem&aacute;s de&nbsp;comprender el concepto de automatizaci&oacute;n y control de procesos, as&iacute; como para adaptarse a las &uacute;ltimas tendencias y tecnolog&iacute;as.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 3 horas de clase por semana sincr&oacute;nica, y&nbsp; 3 horas de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<p>De acuerdo al programa mencionado, los estudiantes desarrollar&aacute;n una amplia variedad de habilidades t&eacute;cnicas en el campo de la electr&oacute;nica, automatizaci&oacute;n y control de procesos. Aqu&iacute; tienes una lista de las habilidades t&eacute;cnicas que los estudiantes adquirir&aacute;n a lo largo del programa:</p>\r\n<ul>\r\n<li><strong>An&aacute;lisis de Circuitos El&eacute;ctricos:</strong> Los estudiantes aprender&aacute;n a analizar circuitos el&eacute;ctricos y electr&oacute;nicos, comprender&aacute;n las leyes de Kirchhoff y ser&aacute;n capaces de resolver problemas relacionados con la corriente el&eacute;ctrica y la tensi&oacute;n.</li>\r\n<li><strong>Dise&ntilde;o de Circuitos Electr&oacute;nicos:</strong> Desarrollar&aacute;n la habilidad para dise&ntilde;ar circuitos electr&oacute;nicos tanto digitales como anal&oacute;gicos, incluyendo la selecci&oacute;n y conexi&oacute;n de componentes adecuados.</li>\r\n<li><strong>Programaci&oacute;n de Microcontroladores: </strong>Adquirir&aacute;n la capacidad de programar microcontroladores (Placas de desarrollo), lo que les permitir&aacute; controlar sistemas y dispositivos electr&oacute;nicos.</li>\r\n<li><strong>Manejo de Instrumentaci&oacute;n:</strong> Aprender&aacute;n a utilizar instrumentos de medici&oacute;n y prueba, como osciloscopios, mult&iacute;metros y generadores de se&ntilde;ales, para evaluar y solucionar problemas en circuitos electr&oacute;nicos.</li>\r\n<li><strong>M&aacute;quinas El&eacute;ctricas:</strong> Ser&aacute;n capaces de distinguir entre distintos tipos de motores y generadores el&eacute;ctricos, as&iacute; como el uso y diversos m&eacute;todos de arranque de motores el&eacute;ctricos.</li>\r\n<li><strong>Programaci&oacute;n de Controladores L&oacute;gicos Programables (PLC):</strong> Conocer&aacute;n el uso de los PLC para automatizar procesos industriales y controlar sistemas en aplicaciones de automatizaci&oacute;n.</li>\r\n<li><strong>Uso de Herramientas de Simulaci&oacute;n:</strong> Aprender&aacute;n a utilizar herramientas de simulaci&oacute;n electr&oacute;nica para modelar y analizar circuitos antes de su implementaci&oacute;n f&iacute;sica.</li>\r\n<li><strong>Dise&ntilde;o de Amplificadores y Filtros: </strong>Ser&aacute;n capaces de dise&ntilde;ar amplificadores y filtros electr&oacute;nicos para aplicaciones espec&iacute;ficas, mejorando la calidad de las se&ntilde;ales y el rendimiento de los sistemas.</li>\r\n<li><strong>Mantenimiento de Equipos Electr&oacute;nicos:</strong> Adquirir&aacute;n habilidades de mantenimiento y resoluci&oacute;n de problemas para identificar y corregir fallas en sistemas electr&oacute;nicos.</li>\r\n<li><strong>Gesti&oacute;n de Proyectos Electr&oacute;nicos:</strong> Desarrollar&aacute;n habilidades de gesti&oacute;n de proyectos, incluyendo la planificaci&oacute;n, ejecuci&oacute;n y documentaci&oacute;n de proyectos de electr&oacute;nica.</li>\r\n<li><strong>Adaptaci&oacute;n a Nuevas Tecnolog&iacute;as: </strong>Aprender&aacute;n a mantenerse actualizados con las tendencias y tecnolog&iacute;as emergentes en el campo de la electr&oacute;nica, lo que les permitir&aacute; adaptarse a los cambios tecnol&oacute;gicos en curso.</li>\r\n<li><strong>Seguridad y Cumplimiento de Normativas: </strong>Estar&aacute;n capacitados para cumplir con normativas de seguridad el&eacute;ctrica y gestionar riesgos en proyectos electr&oacute;nicos, asegurando pr&aacute;cticas seguras y &eacute;ticas en su trabajo.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Perfil profesional&nbsp;</h2>\r\n<p>Al completar el programa, los estudiantes habr&aacute;n adquirido las habilidades,&nbsp;conocimientos y competencias necesarias para desempe&ntilde;arse como&nbsp;t&eacute;cnicos en electr&oacute;nica, automatizaci&oacute;n y control de procesos.</p>\r\n<p><strong>Fundamentos de Electr&oacute;nica:</strong> Los estudiantes ser&aacute;n capaces de&nbsp;comprender los principios b&aacute;sicos de la electr&oacute;nica, analizar circuitos&nbsp;el&eacute;ctricos y trabajar con componentes electr&oacute;nicos.</p>\r\n<p><strong>Electr&oacute;nica Anal&oacute;gica:</strong> Ser&aacute;n competentes en el dise&ntilde;o y mantenimiento&nbsp;de circuitos anal&oacute;gicos, incluyendo amplificadores operacionales y circuitos&nbsp;con transistores.<br>Electr&oacute;nica Digital: Tendr&aacute;n la capacidad de dise&ntilde;ar, implementar y&nbsp;depurar circuitos digitales.</p>\r\n<p><strong>Sensores y Actuadores:</strong> Tendr&aacute;n la capacidad de distinguir entre los&nbsp;diversos tipos de sensores y actuadores, as&iacute; como su uso y aplicaciones en&nbsp;diversos proyectos.</p>\r\n<p><strong>Microcontroladores y Microprocesadores: </strong>Conocer&aacute;n la programaci&oacute;n y&nbsp;el uso de placas de desarrollo, as&iacute; como implementar proyectos pr&aacute;cticos&nbsp;basados en estos dispositivos.</p>\r\n<p><strong>Electr&oacute;nica de Potencia:</strong> Tendr&aacute;n conocimientos sobre dispositivos y&nbsp;convertidores de potencia, control y regulaci&oacute;n de sistemas de potencia, y&nbsp;aplicaciones en eficiencia energ&eacute;tica y energ&iacute;as renovables.</p>\r\n<p><strong>M&aacute;quinas El&eacute;ctricas:</strong> Podr&aacute;n distinguir entre diversos tipos de motores y<br>generadores, as&iacute; como su uso y aplicaciones.</p>\r\n<p><strong>Automatizaci&oacute;n y Control:</strong> Ser&aacute;n capaces de comprender y aplicar&nbsp;conceptos de automatizaci&oacute;n y control.</p>\r\n<p><strong>Proyectos y Pr&aacute;cticas:</strong> Desarrollar&aacute;n la capacidad de llevar a cabo&nbsp;proyectos de electr&oacute;nica aplicada, realizar pr&aacute;cticas en laboratorios&nbsp;especializados, resolver problemas y presentar y documentar proyectos de&nbsp;manera efectiva.</p>\r\n<p><strong>Seguridad y Normativas en Electr&oacute;nica: </strong>Estar&aacute;n conscientes de las&nbsp;normativas y est&aacute;ndares de seguridad el&eacute;ctrica, gestionar&aacute;n riesgos en&nbsp;proyectos electr&oacute;nicos y actuar&aacute;n con &eacute;tica y responsabilidad profesional.</p>\r\n<p><strong>Tendencias y Tecnolog&iacute;as Emergentes: </strong>Estar&aacute;n actualizados en las&nbsp;&uacute;ltimas tendencias de la electr&oacute;nica, podr&aacute;n participar en investigaci&oacute;n y&nbsp;desarrollo en electr&oacute;nica y adaptarse a las nuevas tecnolog&iacute;as con&nbsp;facilidad.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico Especializado en Explotaci&oacute;n Pecuaria con &eacute;nfasis en Desarrollo de Fincas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones y plataformas de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69a9bf6889cfd3.61610117-Electronica.png', '2026-03-05 00:19:40', 7, 0, '', '', '', 0),
(72, 18, 'Técnico Especializado en Explotación Pecuaria con énfasis en Desarrollo de Fincas', 'Desarrolla habilidades y conocimientos para la implementación de una gestión eficiente en proyectos pecuarios diversificados enfocados en el desarrollo sostenible, la productividad y la rentabilidad económica.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">Contar&aacute; con las habilidades necesarias para implementar, administrar y mejorar la producci&oacute;n pecuaria en diversas &aacute;reas, incluyendo ganado de cr&iacute;a, ganado lechero y con doble prop&oacute;sito, cerdos, aves de corral, acuicultura, especies menores. Adem&aacute;s, estar&aacute; preparado para contrarrestar desaf&iacute;os y problemas comunes en la industria pecuaria, promoviendo pr&aacute;cticas sostenibles y &eacute;ticas.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 3 horas de clase por semana sincr&oacute;nica, y&nbsp; 3 horas de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Gesti&oacute;n Agropecuaria Integral: Planificaci&oacute;n de proyectos agropecuarios, manejo de recursos, control de costos, implementaci&oacute;n de pr&aacute;cticas sostenibles y desarrollo de estrategias de mejora continua.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Conocimientos en Comercializaci&oacute;n y Ventas: Desarrollo de estrategias de marketing, conocimiento de canales de distribuci&oacute;n, comprensi&oacute;n del mercado y capacidad para promover productos agropecuarios de manera efectiva.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Competencias T&eacute;cnicas en Manejo Animal: Cuidado de animales de diferentes especies, control de enfermedades, alimentaci&oacute;n y nutrici&oacute;n animal, manejo reproductivo y gen&eacute;tico.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Habilidades de Planificaci&oacute;n y Gesti&oacute;n: Capacidad para desarrollar planes de manejo de proyectos agropecuarios, establecer objetivos a corto y largo plazo, y adaptarse a las necesidades cambiantes del mercado y del entorno agropecuario.</li>\r\n<li>Habilidades de Comunicaci&oacute;n y Trabajo en Equipo: Capacidad para trabajar en equipo y comunicarse de manera efectiva con&nbsp; personal, proveedores y clientes, promoviendo un entorno de trabajo colaborativo y eficiente.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Perfil profesional&nbsp;</h2>\r\n<p>El estudiante que complete el programa estar&aacute; preparado para trabajar en el desarrollo del sector pecuario con un enfoque integral en la gesti&oacute;n de proyectos diversificados. <br>Contar&aacute; con las habilidades necesarias para implementar, administrar y mejorar la producci&oacute;n pecuaria en diversas &aacute;reas, incluyendo ganado de cr&iacute;a, ganado lechero y con doble prop&oacute;sito, cerdos, aves de corral, acuicultura, especies menores. Adem&aacute;s, estar&aacute; preparado para contrarrestar desaf&iacute;os y problemas comunes en la industria pecuaria, promoviendo pr&aacute;cticas sostenibles y &eacute;ticas.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico Especializado en Explotaci&oacute;n Pecuaria con &eacute;nfasis en Desarrollo de Fincas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial y/o virtual.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones y plataformas de primer nivel.</li>\r\n<li>Giras y taller pr&aacute;cticos.&nbsp;</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li>Virtual, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual: </strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69a9c010350216.59802013-explotación pecuaria.png', '2026-03-05 00:43:45', 7, 0, '', '', '', 0),
(73, 18, 'Técnico Especializado en Arquitectura Digital y Diseño Espacial', 'Forma profesionales competentes en la interpretación, diseño y representación gráfica de proyectos arquitectónicos, utilizando herramientas digitales avanzadas, técnicas de dibujo 2D y modelado 3D, aplicadas a la arquitectura y el diseño espacial.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">El prograna brinda lo necesario para ingresar al campo laboral como un asistente altamente competente, capaz de abordar los desaf&iacute;os del dise&ntilde;o arquitect&oacute;nico y contribuir al &eacute;xito de proyectos de construcci&oacute;n de manera eficiente y profesional.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 3 horas de clase por semana sincr&oacute;nica, y&nbsp; 3 horas de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Dominio de la lectura e interpretaci&oacute;n de planos arquitect&oacute;nicos.</li>\r\n<li>Manejo competente de AutoCAD en niveles b&aacute;sico e intermedio-avanzado.</li>\r\n<li>Capacidades de modelado tridimensional de proyectos arquitect&oacute;nicos.</li>\r\n<li>Habilidades para la conceptualizaci&oacute;n y dise&ntilde;o de interiores funcionales y est&eacute;ticos.</li>\r\n<li>Un portafolio b&aacute;sico de proyectos digitales que respalde su perfil profesional.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Perfil profesional&nbsp;</h2>\r\n<p>El egresado del T&eacute;cnico Especializado en Arquitectura Digital y Dise&ntilde;o Espacial ser&aacute; capaz de interpretar planos arquitect&oacute;nicos, utilizar herramientas digitales avanzadas para el dise&ntilde;o 2D y 3D, desarrollar representaciones espaciales precisas, y crear propuestas de dise&ntilde;o de interiores. Estar&aacute; capacitado para desempe&ntilde;arse en estudios de arquitectura, empresas de construcci&oacute;n, firmas de dise&ntilde;o de interiores, o de manera independiente como dibujante t&eacute;cnico o asistente de dise&ntilde;o.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico Especializado en Arquitectura Digital y Dise&ntilde;o Espacial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones y plataformas de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ab294b373870.44595187-Arquitectura Digital.png', '2026-03-05 23:19:12', 7, 0, '', '', '', 0),
(74, 18, 'Programa Especializado en Grooming y Estética Canina', 'Prepara especialistas en cuidado y grooming de mascotas con un enfoque emprendedor, proporcionando conocimientos teóricos y habilidades prácticas necesarias para llevar a cabo procedimientos de grooming de manera profesional y segura, y capacitándolos para emprender en el sector con un alto nivel de competencia.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">Este especializado tiene un enfoque intensivo y espec&iacute;fico, se centra en los aspectos esenciales del cuidado y grooming de las mascotas (canino y gatos), proporciona a los estudiantes conocimientos t&eacute;cnicos, habilidades pr&aacute;cticas y una introducci&oacute;n al emprendimiento en el campo.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">10 meses con una duraci&oacute;n de 3 horas de clase por semana sincr&oacute;nica, y&nbsp; 3 horas de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Proporcionar a los estudiantes una comprensi&oacute;n&nbsp;profunda de los fundamentos y t&eacute;cnicas esenciales del grooming canino.</li>\r\n<li>Desarrollar habilidades pr&aacute;cticas mediante talleres supervisados que aborden aspectos clave, desde la limpieza de o&iacute;dos hasta&nbsp; cortes de pelo espec&iacute;ficos para perros.</li>\r\n<li>Fomentar habilidades empresariales mediante el estudio de salud ocupacional, consejos para la gesti&oacute;n de empresas y el desarrollo de un plan de negocios emprendedor.</li>\r\n<li>Brindar experiencia pr&aacute;ctica en sal&oacute;n de grooming (aula) para que los estudiantes se familiaricen con el entorno laboral y&nbsp; desarrollen habilidades de atenci&oacute;n al cliente.</li>\r\n<li>Desarrollar en los estudiantes el conocimiento de estilos espec&iacute;ficos para diversas razas, fomentando la creatividad y la&nbsp; adaptabilidad en el dise&ntilde;o de cortes de pelo.</li>\r\n<li>Preparar a los estudiantes en el grooming de la raza Poodle, proporcionando t&eacute;cnicas y estilos espec&iacute;ficos.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Perfil profesional&nbsp;</h2>\r\n<ul>\r\n<li>Capacidad para realizar procedimientos de grooming de manera profesional, incluyendo ba&ntilde;os, cortes de pelo espec&iacute;ficos para cada raza, cuidado de u&ntilde;as y limpieza de o&iacute;dos.</li>\r\n<li>Habilidad para utilizar herramientas y equipos de grooming de forma segura y efectiva.</li>\r\n<li>Habilidades Empresariales.</li>\r\n<li>Conocimientos en salud ocupacional y gesti&oacute;n de empresas relacionadas con el cuidado de mascotas.</li>\r\n<li>Capacidad para desarrollar y presentar proyectos emprendedores en el&nbsp;sector de grooming.</li>\r\n<li>Adaptabilidad y creatividad en grooming.</li>\r\n<li>Habilidad para adaptarse a diferentes tipos de pelaje y razas, aplicando t&eacute;cnicas espec&iacute;ficas de grooming.</li>\r\n<li>Creatividad en el dise&ntilde;o de estilos y cortes de pelo para cumplir con las preferencias de los clientes.</li>\r\n<li>&Eacute;nfasis en Poodle.</li>\r\n<li>Habilidad en el grooming de la raza Poodle, con habilidades para realiza&nbsp;cortes de pelo espec&iacute;ficos y adaptarse a las preferencias de los due&ntilde;os.</li>\r\n<li>Capacidad para ofrecer servicios especializados que destacan la versatilidad de los Poodles y otras razas.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico Especializado en Arquitectura Digital y Dise&ntilde;o Espacial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones y plataformas de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ab2a0767ea91.35392190-Grooming.png', '2026-03-06 03:46:50', 7, 0, '', '', '', 0),
(75, 18, 'Técnico Especializado en Control y Atención de Plagas', 'Analiza y acciona los mecanismos de control y atención de plagas y su incidencia en el medio ambiente y en la salud humana.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">Proporciona al estudiante aspectos generales desde las caracter&iacute;sticas b&aacute;sicas de las diferentes plagas y su forma de control, hasta las valoraciones ambientales mediante el an&aacute;lisis de los mejores mecanismos de abordaje y atenci&oacute;n de acuerdo con las tendencias&nbsp;modernas sobre este tema.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 3 horas de clase por semana sincr&oacute;nica, y&nbsp; 3 horas de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Identificar aspectos generales de las plagas y los diferentes mecanismos de control.</li>\r\n<li>Diferenciar las propiedades f&iacute;sicoqu&iacute;micas contenidas en los productos del mercado para el control de plagas y su efecto en el ambiente.</li>\r\n<li>Distinguir aspectos regulatorios de riesgos en el control de plagas basados en la correcta ejecuci&oacute;n.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Perfil profesional&nbsp;</h2>\r\n<ul>\r\n<li>Asesorar empresas productoras relacionadas con el agro.</li>\r\n<li>Desarrollar su propia empresa para la prestaci&oacute;n de servicios relacionados con el control de plagas en diversos sectores y actividades.</li>\r\n<li>Asistir empresas para la creaci&oacute;n de programas preventivos en el control de plagas.</li>\r\n<li>Apoyar procesos de certificaci&oacute;n y calidad relacionados con el control de plagas en diferentes actividades econ&oacute;micas.</li>\r\n<li>Prestar servicios de capacitaci&oacute;n a las empresas que requieran conocimientos espec&iacute;ficos en el control y atenci&oacute;n de plagas.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico Especializado en Control y Atenci&oacute;n de Plagas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial y/o virtual.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones y plataformas de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li><strong>Virtual</strong>, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ab2b50df2a01.22161286-Control y Atención de Plagas.png', '2026-03-06 04:20:55', 7, 0, '', '', '', 0),
(76, 18, 'Técnico Especializado en Administración Aduanera', 'Domina la dinámica del comercio internacional con especial énfasis en la logística aduanera, según la normativa costarricense vigente.', '<h2 dir=\"ltr\">Descripci&oacute;n.</h2>\r\n<p>Proporciona al estudiante los conocimientos, habilidades y aptitudes necesarias para trabajar en empresas que desarrollen procesos de comercio internacional, tener las destrezas para comprender las principales operaciones de la gesti&oacute;n aduanera y la log&iacute;stica portuaria.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso.</h2>\r\n<p>12 meses con una duraci&oacute;n de 3 horas de leci&oacute;n sincr&oacute;nica semanal y 3 horas de trabajo asincr&oacute;nico semanal.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir.</h2>\r\n<ul>\r\n<li>Conocer las generalidades del comercio internacional y la administraci&oacute;n aduanera.</li>\r\n<li>Determinar aquellos elementos esenciales de la Administraci&oacute;n Aduanera y su normativa fundamental.</li>\r\n<li>Determinar los principales tr&aacute;mites de importaci&oacute;n y exportaci&oacute;n de mercanc&iacute;as que se movilizan por medio de fronteras, puertos y aeropuertos.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Perfil profesional.</h2>\r\n<p>La persona egresada del programa t&eacute;cnico, podr&aacute; dar asistencia administrativa y desempe&ntilde;arse de una forma efectiva en empresas relacionadas con el comercio internacional, en organizaciones como las siguientes:</p>\r\n<ul>\r\n<li>Empresas importadoras de mercanc&iacute;as.</li>\r\n<li>Empresas con internacionalizaci&oacute;n de ventas.</li>\r\n<li>Empresas o auxiliares de la funci&oacute;n p&uacute;blica aduanera como almacenes&nbsp;fiscales, consolidadores de carga internacional, transportistas, entre otros.</li>\r\n<li>Empresas en zonas francas.&nbsp;</li>\r\n<li>Emprendimientos con miras a la&nbsp;exportaci&oacute;n.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Beneficios.</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico Especializado en Administraci&oacute;n Aduanera.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial y/o virtual.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones y plataformas de primer nivel.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Modalidad.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li>Virtual, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Plataformas.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Requisitos.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ab2c767be068.24605915-Adunera.png', '2026-03-06 04:31:16', 7, 0, '', '', '', 0),
(77, 18, 'Técnico Especializado en Ciencias Agrícolas con énfasis en Agronegocios', 'Diseña planes de negocios basados en actividades propias del sector agrícola como alternativa de producción sostenible y económica.\r\n', '<h2 dir=\"ltr\">Descripci&oacute;n.</h2>\r\n<p>El programa consta de 12 cursos que le proporcionar&aacute;n al estudiante los conocimientos, habilidades y destrezas necesarias para desarrollar alternativas de actividades econ&oacute;micas derivadas el agro.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del programa.</h2>\r\n<p>12 meses con una duraci&oacute;n de 3 horas de clase por semana sincr&oacute;nica, y&nbsp; 3 horas de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir.</h2>\r\n<ul>\r\n<li>Crear planes de negocios basados en actividades propias del sector agr&iacute;cola como alternativa de producci&oacute;n sostenible y econ&oacute;mica.&nbsp;</li>\r\n<li>Dominar las generalidades de las ciencias agr&iacute;colas y su impacto social y econ&oacute;mico.</li>\r\n<li>Comprende las principales &aacute;reas de estudio de las ciencias agr&iacute;colas y sus tendencias para mejorar la productividad de una forma sustentable.</li>\r\n<li>Dise&ntilde;a modelos y alternativas de negocio a partir de procesos productivos vinculados con el sector agr&iacute;cola.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Perfil profesional.</h2>\r\n<p>La persona egresada del programa de t&eacute;cnico superior podr&aacute; dar asistencia administrativa y desempe&ntilde;arse de una forma efectiva en empresas u organizaciones que desarrollen actividades como las siguientes:<br>&bull; Emprendimientos basados en el agro.<br>&bull; Empresas agr&iacute;colas con comercializaci&oacute;n local.<br>&bull; Empresas relacionadas con exportaciones de productos agr&iacute;colas.<br>&bull; Entidades financieras que desarrollen l&iacute;neas de cr&eacute;dito relacionados con los agronegocios.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios.</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico Especializado en Ciencias Agr&iacute;colas con &eacute;nfasis en Agronegocios.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial y/o virtual.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones y plataformas de primer nivel.&nbsp;\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Modalidad.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li>Virtual, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Plataformas.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Requisitos.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ab2cef3f8651.59871342-Ciencias Agrícolas.png', '2026-03-06 04:41:44', 7, 0, '', '', '', 0);
INSERT INTO `posts` (`id_post`, `id_category`, `title`, `synopsis`, `content`, `main_image`, `created_at`, `id_user`, `orden`, `instructor_name`, `instructor_title`, `instructor_photo`, `show_in_instructors`) VALUES
(78, 18, 'Técnico Especializado en Asistencia en Administración Hotelera', 'Brinda los conocimientos fundamentales, capacidades y aspectos técnicos para formar conocedores en el campo de la Administración Hotelera con la idoneidad necesaria para ocupar puestos de asistencia administrativa y en servicio al cliente turístico.', '<h2 dir=\"ltr\">Descripci&oacute;n.</h2>\r\n<p>Se compone conjunto de programas que brindan los conocimientos fundamentales, capacidades y aspectos t&eacute;cnicos para formar conocedores en el campo de la Administraci&oacute;n Hotelera con la idoneidad necesaria para ocupar puestos de asistencia administrativa y en servicio al cliente tur&iacute;stico y afrontar las exigencias del mercado laboral y el perfil laboral de cualquier compa&ntilde;&iacute;a tanto p&uacute;blica como privada.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del programa.</h2>\r\n<p>12 meses con una duraci&oacute;n de 3 horas de clase por semana sincr&oacute;nica y 3 horas de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir.</h2>\r\n<ul>\r\n<li>Conocimientos, capacidades y aspectos t&eacute;cnicos y tecnol&oacute;gicos en el campo de la Administraci&oacute;n Hotelera.</li>\r\n<li>Idoneidad para ocupar puestos de asistencia administrativa y en servicio al cliente tur&iacute;stico ya que cubrir&aacute; el perfil laboral de cualquier compa&ntilde;&iacute;a tanto p&uacute;blica como privada.</li>\r\n<li>Conocimientos t&eacute;cnicos y administrativos para desenvolverse en actividades de relaciones humanas y de interacci&oacute;n cultural&nbsp;como colaborador o emprendedor.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Perfil del estudiante.</h2>\r\n<p>Debe poseer habilidades para mostrar facilidad en los siguientes puntos:<br>&bull; Buena relaci&oacute;n con las personas.<br>&bull; Persona proactiva, espont&aacute;nea y extrovertida.<br>&bull; Comprensi&oacute;n de la relevancia del servicio al cliente y la importante relaci&oacute;n con la actividad hotelera-tur&iacute;stica.<br>&bull; Aprecio e inter&eacute;s por conocer y preservar el patrimonio y la identidad cultural, para darla a conocer.<br>&bull; Aprecio por conocer y preservar el patrimonio natural.<br>&bull; Esp&iacute;ritu de aprendizaje y busca aprender a comunicarse utilizando diferentes formas de comunicaci&oacute;n e idiomas. -Apertura e inter&eacute;s para adquirir conocimiento de procesos acad&eacute;micos y administrativos.<br>&bull; Disposici&oacute;n para aprender y trabajar con TIC&rsquo;s.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios.</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico Especializado en Asistencia en Administraci&oacute;n Hotelera.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial y/o virtual.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones y plataformas de primer nivel.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Modalidad.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li>Virtual, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Plataformas.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Requisitos.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ac795f45d533.36391438-Hotelera.png', '2026-03-06 05:05:29', 7, 0, '', '', '', 0),
(79, 18, 'Técnico Especializado en Supervisión y Control de Calidad', 'Forma profesionales altamente calificados y éticos que, tras completar el programa, sean capaces de liderar iniciativas de control de calidad, mejora de procesos productivos y optimización del rendimiento laboral en organizaciones, contribuyendo así al éxito y la competitividad de las mismas en un entorno empresarial en constante evolución.', '<h2 dir=\"ltr\">Descripci&oacute;n.</h2>\r\n<p>Formar profesionales altamente calificados y &eacute;ticos que, tras completar el programa, sean capaces de liderar iniciativas de control de calidad, mejora de procesos productivos y optimizaci&oacute;n del rendimiento laboral en organizaciones, contribuyendo as&iacute; al &eacute;xito y la&nbsp;competitividad de las mismas en un entorno empresarial en constante evoluci&oacute;n.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso.</h2>\r\n<p>12 meses con una duraci&oacute;n de 3 horas de clase por semana sincr&oacute;nica y 3 horas de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir.</h2>\r\n<p><strong>Habilidades T&eacute;cnicas.</strong></p>\r\n<ul>\r\n<li>Control de Calidad:&nbsp; capacidad de evaluar y aplicar t&eacute;cnicas avanzadas de control de calidad para garantizar la excelencia en los productos y servicios.</li>\r\n<li>Mejora Continua: Tendr&aacute;n la capacidad de identificar oportunidades de mejora en los procesos productivos y aplicar&nbsp; metodolog&iacute;as como Six Sigma o Lean para optimizar la eficiencia y reducir costos.</li>\r\n<li>Gesti&oacute;n de Proyectos: Gestionar proyectos de mejora de procesos desde la concepci&oacute;n hasta la implementaci&oacute;n, asegurando el cumplimiento de los objetivos.&nbsp;</li>\r\n<li>An&aacute;lisis de Datos: Ser&aacute;n expertos en recopilar, analizar y utilizar datos para tomar decisiones informadas y medir el rendimiento.</li>\r\n<li>Comunicaci&oacute;n efectiva y habilidades blandas: comunicar claramente los resultados de sus an&aacute;lisis y propuestas de mejora a los<br>equipos de trabajo y la direcci&oacute;n que conlleva la misma.</li>\r\n</ul>\r\n<p><strong>Conocimientos espec&iacute;ficos.</strong></p>\r\n<ul>\r\n<li>Normativas de Calidad: normativas y&nbsp;est&aacute;ndares de calidad internacionales y nacionales relevantes para la&nbsp;industria.</li>\r\n<li>Tecnolog&iacute;as de Control: Conocer n las &uacute;ltimas tecnolog&iacute;as y herramientas de control de calidad, as&iacute; como sistemas de informaci&oacute;n empresarial.</li>\r\n<li>Gesti&oacute;n de Procesos: principios de gesti&oacute;n de procesos, dise&ntilde;o de experimentos y automatizaci&oacute;n industrial.</li>\r\n<li>Psicolog&iacute;a Organizacional: Base en psicolog&iacute;a organizacional para promover un ambiente laboral saludable y productivo.<br>&Eacute;tica Profesional: compromiso con altos est&aacute;ndares &eacute;ticos en todas sus actividades laborales.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">&nbsp;Perfil profesional.</h2>\r\n<p>El T&eacute;cnico en Control de Calidad es un profesional altamente capacitado y vers&aacute;til que se destaca en garantizar la calidad de los productos y servicios, optimizar los procesos industriales y promover un entorno laboral eficiente y productivo.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios.</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico Especializado en Supervisi&oacute;n y Control de Calidad.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial y/o virtual.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones y plataformas de primer nivel.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Modalidad.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li>Virtual, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Plataformas.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Requisitos.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ac79e1637796.96445068-Supervisión y Control de Calidad.png', '2026-03-06 05:57:03', 7, 0, '', '', '', 0),
(80, 18, 'Técnico Especializado en Marketing Digital y Social Media', 'Provee al estudiante herramientas aplicadas a su área de conocimiento y trabajo, relacionadas con el marketing tradicional y digital que contribuyan con la atracción de nuevos clientes y dar seguimiento a sus actuales prospectos.', '<h2 dir=\"ltr\">Descripci&oacute;n.</h2>\r\n<p>El programa contiene los elementos esenciales que un estudiante requiere para una s&oacute;lida comprensi&oacute;n te&oacute;rica y habilidades pr&aacute;cticas en marketing digital, enfocados en la creaci&oacute;n, implementaci&oacute;n y an&aacute;lisis de estrategias efectivas en redes sociales y otros canales, de&nbsp;manera que pueda dise&ntilde;ar su propio plan de marketing para atraer, mantener y dar seguimiento a sus clientes, sean estos personas o instituciones en modelos B2C o C2C (de negocio a cliente o de persona a cliente).</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso.</h2>\r\n<p>7 meses.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir .</h2>\r\n<ul>\r\n<li>Posicionar en el mercado de trabajo su modelo de negocio correspondiente, ya sea comovnegocio nuevo o consolidado, o bien como trabajador independiente mediante las herramientas del mercadeo tradicional y digital.</li>\r\n<li>Incorporar las principales herramientas de mercadeo digital en sus modelos de negocios: redes sociales, RP, venta personal, e-mail marketing, WA, SEO y SEM.</li>\r\n<li>Dise&ntilde;ar una campa&ntilde;a de marketing digital para redes sociales.</li>\r\n<li>Realizar an&aacute;lisis de mercado b&aacute;sico basados en estad&iacute;sticas disponibles en redes sociales.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Beneficios.</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico Especializado en Marketing Digital y Social Media.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial y/o virtual.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones y plataformas de primer nivel.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Modalidad.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li>Virtual, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Plataformas.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Requisitos.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ac7a0d55a391.94504893-Marketing Digital y Social Media.png', '2026-03-06 06:09:22', 7, 0, '', '', '', 0),
(81, 18, 'Programa Especializado en Corte y Confección por Talla - Nivel I.', 'Capacitar a los participantes en corte y confección de prendas con patrones por tallas, proporcionándoles los conocimientos y habilidades necesarios para desarrollarse con eficacia en el amplio mundo de la costura.', '<h2 dir=\"ltr\">Descripci&oacute;n.</h2>\r\n<p>Capacitar a los participantes en corte y confecci&oacute;n de prendas con patrones por tallas, proporcion&aacute;ndoles los conocimientos y habilidades necesarios para desarrollarse con eficacia en el amplio mundo de la costura.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso.</h2>\r\n<p>4 meses.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir.</h2>\r\n<ul>\r\n<li>Desarrollar habilidades en la creaci&oacute;n de prendas con patrones por talla que le permitan crear y confeccionar variedad de dise&ntilde;os.</li>\r\n<li>Dotar con t&eacute;cnicas practicas, f&aacute;ciles y modernas en el mundo de la costura.</li>\r\n<li>Fomentar la capacidad de creaci&oacute;n y confecci&oacute;n de prendas con patrones por tallas que le permitan alcanzar una producci&oacute;n m&aacute;s efectiva.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Perfil profesional.</h2>\r\n<ul>\r\n<li>Competencia en creaci&oacute;n y confecci&oacute;n de prendas por talla.&nbsp;</li>\r\n<li>Dominio en T&eacute;cnicas en confecci&oacute;n de prendas.&nbsp;</li>\r\n<li>Uso correcto de patrones.&nbsp;</li>\r\n<li>Modificaci&oacute;n de patrones.&nbsp;</li>\r\n<li>Capacidad creativa para dise&ntilde;ar prendas.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Beneficios.</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como profesional en corte y confecci&oacute;n.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones y plataformas de primer nivel.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Modalidad.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li>Virtual, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Plataformas.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">Contar con maquina de coser propia.</li>\r\n</ul>', 'post_69ac7a781738c3.51523585-Corte y Confección por Talla.png', '2026-03-06 06:19:49', 7, 0, '', '', '', 0),
(82, 18, 'Técnico Especializado en Estimulación Temprana', 'Programa de formación técnica orientado al desarrollo de competencias teóricas y prácticas para la atención integral del desarrollo infantil desde el nacimiento hasta los 6 años de edad.', '<h2 dir=\"ltr\">Descripci&oacute;n.</h2>\r\n<p>El programa prepara al estudiantado para dise&ntilde;ar, aplicar y evaluar estrategias de estimulaci&oacute;n temprana, considerando el desarrollo motor, cognitivo, comunicativo, socioemocional y sensorial del ni&ntilde;o y la ni&ntilde;a, bajo principios cient&iacute;ficos, &eacute;ticos e inclusivos.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del programa.</h2>\r\n<p>12 meses con una duraci&oacute;n de 3 horas de clase por semana sincr&oacute;nica, y&nbsp; 3 horas de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir.</h2>\r\n<ul>\r\n<li>Analizar los fundamentos del desarrollo infantil y la estimulaci&oacute;n temprana en el contexto costarricense.</li>\r\n<li>Aplicar conocimientos b&aacute;sicos de neurodesarrollo y desarrollo infantil para la planificaci&oacute;n de actividades de&nbsp; estimulaci&oacute;n.&nbsp;</li>\r\n<li>Dise&ntilde;ar e implementar estrategias de estimulaci&oacute;n temprana por &aacute;reas del desarrollo.&nbsp;</li>\r\n<li>Identificar se&ntilde;ales de alerta en el desarrollo infantil y canalizar adecuadamente los casos.</li>\r\n<li>Promover la participaci&oacute;n de la familia en los procesos de estimulaci&oacute;n temprana.</li>\r\n<li>Aplicar principios &eacute;ticos, de inclusi&oacute;n y de protecci&oacute;n de la ni&ntilde;ez en la pr&aacute;ctica profesional.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Beneficios.</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico Especializado en Estimulaci&oacute;n Temprana.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial y/o virtual.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones y plataformas de primer nivel.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Modalidad.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li>Virtual, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Plataformas.&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ac7b18393d90.74556977-Estimulación Temprana.png', '2026-03-06 06:35:14', 7, 0, '', '', '', 0),
(83, 17, 'Diseño Estratégico del Aprendizaje potencializado con Inteligencia Artificial', 'Consolidar las competencias en los educadores para integrar herramientas de inteligencia artificial en el planeamiento docente, así como su respectiva evaluación, mediante el prompt, automatizando la planificación, valoración y personalización del aprendizaje.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p>Empoderar al educador como un \"Arquitecto del Aprendizaje\", que utiliza la IA como un&nbsp;copiloto inteligente para dise&ntilde;ar, implementar y evaluar experiencias educativas de alto&nbsp;impacto, eficientes y personalizadas.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">2 meses con una duraci&oacute;n de 3 horas de clase por semana sincr&oacute;nica, y &nbsp;3 horas de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Identificar los fundamentos del planeamiento educativo y su relaci&oacute;n con la inteligencia&nbsp;artificial.</li>\r\n<li>Aplicar herramientas de IA para la elaboraci&oacute;n de unidades did&aacute;cticas, r&uacute;bricas y estrategias&nbsp;de evaluaci&oacute;n.</li>\r\n<li>Dise&ntilde;ar propuestas pedag&oacute;gicas innovadoras apoyadas en IA que respondan a las&nbsp;necesidades del contexto educativo.</li>\r\n<li>Dominar los Fundamentos de la IA Aplicada, aplicando los conceptos clave de la IA generativa&nbsp;y los modelos ling&uuml;&iacute;sticos (LLM) en contextos pedag&oacute;gicos.</li>\r\n<li>Construir Prompts de Alta Precisi&oacute;n, efectivos para generar recursos educativos, unidades&nbsp;did&aacute;cticas, y estrategias de evaluaci&oacute;n alineadas con los objetivos curriculares.</li>\r\n<li>Innovar en la creaci&oacute;n de contenido utilizando un ecosistema de herramientas de IA para&nbsp;producir materiales did&aacute;cticos multimodales (texto, imagen, video) que respondan a diversos&nbsp;estilos de aprendizaje.</li>\r\n<li>Sistematizar la Evaluaci&oacute;n con retroalimentaci&oacute;n, implementado herramientas de IA para&nbsp;automatizar la creaci&oacute;n de instrumentos de evaluaci&oacute;n (r&uacute;bricas, cuestionarios) y para generar&nbsp;feedback inmediato y personalizado a los estudiantes.</li>\r\n<li>Desarrollar un Marco &Eacute;tico de Actuaci&oacute;n, aplicando los principios &eacute;ticos para un uso&nbsp;responsable de la IA, garantizando la equidad, la privacidad de los datos y la integridad&nbsp;acad&eacute;mica en el aula.</li>\r\n<li>Conceptos clave de IA aplicada&nbsp;a la educaci&oacute;n.</li>\r\n<li>Herramientas como ChatGPT,&nbsp;Copilot, Canva, Quillionz, ClassPoint,&nbsp;etc.</li>\r\n<li>Dise&ntilde;o de clases asistidas por IA.</li>\r\n<li>Evaluaci&oacute;n automatizada y&nbsp;retroalimentaci&oacute;n inteligente.</li>\r\n<li>&Eacute;tica y responsabilidad en el&nbsp;uso de IA en el aula.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">8 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar manejar el Dise&ntilde;o Estrat&eacute;gico del Aprendizaje potencializado con Inteligencia Artificial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ab3c3fcd73f4.47865636-Diseño Estratégico del Aprendizaje potencializado con Inteligencia Artificial_Mesa de trabajo 1 copia 25.png', '2026-03-06 20:38:22', 6, 0, '', '', '', 0),
(84, 17, 'Destrezas Computacionales de 0 a 100', 'Aprende los aspectos computacionales, con el fin de aplicarlo a las labores del área de oficina para generar competencias que permitan desarrollar mejores actitudes y aptitudes en cualquier empresa ya sea pública o privada.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p>Brindar el conocimiento necesario, con el objetivo de otorgar los conocimientos que les permitan&nbsp;conocer nociones b&aacute;sicas de hardware y software, as&iacute; como el uso de aplicaciones Ofim&aacute;ticas&nbsp;de la Suite de Microsoft 365, adem&aacute;s de otras plataformas de desarrollo digital y la seguridad de&nbsp;la informaci&oacute;n.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">4 meses con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Brindar el conocimiento necesario a los&nbsp;estudiantes que le permitan conocer&nbsp;nociones b&aacute;sicas de hardware y software,&nbsp;as&iacute; como el uso de aplicaciones Ofim&aacute;ticas&nbsp;de la Suite de Microsoft 365, adem&aacute;s de&nbsp;otras plataformas de desarrollo digital y la&nbsp;seguridad de la informaci&oacute;n.</li>\r\n<li>Ense&ntilde;ar mediante el uso de diferentes&nbsp;recursos, nociones b&aacute;sicas de software y&nbsp;hardware, as&iacute; como el conocimiento b&aacute;sico&nbsp;del equipo y sus cuidados.</li>\r\n<li>Conocer el alcance general que tiene el uso&nbsp;de la Suite de Microsoft 365(procesador de&nbsp;textos WORD, PowerPoint y Excel) y de c&oacute;mo&nbsp;integrarlo en el quehacer diario del trabajo y&nbsp;administraci&oacute;n de oficinas.</li>\r\n<li>Conocer el uso de plataformas en la nube&nbsp;(Cloud) tales como Canva, Create Vista, Prezi&nbsp;para crear contenido digital.</li>\r\n<li>Dotar a los estudiantes el conocimiento de las principales herramientas de prevenci&oacute;n de la seguridad en la Web.</li>\r\n<li>Mostrar las nociones computacionales en que&nbsp;involucra el quehacer secretarial, as&iacute; como la&nbsp;correcta digitaci&oacute;n y redacci&oacute;n de documentos.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">16 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades en Destrezas Computacionales de 0 a 100.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ab44dd3dee00.64148508-Destrezas Computacionales de 0 a 100.png', '2026-03-06 21:19:25', 6, 0, '', '', '', 0),
(85, 17, 'Curso Integral de Soporte Vital Asistido', 'Desarrollar las herramientas teóricas y prácticas necesarias para asistir de manera eficaz al profesional de salud durante las etapas pre, trans y post atención del paciente.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p>Este curso est&aacute; dise&ntilde;ado para brindar al participante los conocimientos te&oacute;ricos y pr&aacute;cticos&nbsp;necesarios para asistir de manera efectiva al profesional de salud durante las distintas fases&nbsp;del proceso asistencial: antes (pre), durante (trans) y despu&eacute;s (post) de la atenci&oacute;n al&nbsp;paciente.<br>Se abordar&aacute;n temas clave como la preparaci&oacute;n del usuario, normas de higiene cl&iacute;nica,&nbsp;principios de asepsia y el correcto acompa&ntilde;amiento durante procedimientos, con &eacute;nfasis&nbsp;en la seguridad del usuario y la calidad del cuidado. Adem&aacute;s, se fortalecer&aacute;n habilidades de&nbsp;comunicaci&oacute;n y conocimiento del equipo t&eacute;cnico, promoviendo el trabajo&nbsp;interdisciplinario. El curso incluye pr&aacute;cticas simuladas en un entorno controlado y&nbsp;supervisado.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">6 semanas con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<p>Brindar al participante las herramientas te&oacute;ricas y pr&aacute;cticas necesarias para asistir de manera&nbsp;eficaz al profesional de salud durante las etapas pre, trans y post atenci&oacute;n del paciente,&nbsp;aplicando principios de asepsia, normas de higiene cl&iacute;nica y protocolos actualizados que&nbsp;garanticen la continuidad del cuidado, la seguridad del usuario y la calidad en los resultados&nbsp;cl&iacute;nicos.</p>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">6 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para manejar el Soporte Vital Asistido</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ab47a257b502.03825025-Curso Integral de Soporte Vital Asistido.png', '2026-03-06 21:31:14', 6, 0, '', '', '', 0);
INSERT INTO `posts` (`id_post`, `id_category`, `title`, `synopsis`, `content`, `main_image`, `created_at`, `id_user`, `orden`, `instructor_name`, `instructor_title`, `instructor_photo`, `show_in_instructors`) VALUES
(86, 17, 'Gestión y manejo de desechos sólidos hospitalarios y principios de técnica aséptica médica y quirúrgica', 'Educar al estudiante sobre la adecuada gestión y manejo de DSH y los principios de técnica aséptica médica y quirúrgica.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p>El curso de <em>Gesti&oacute;n y manejo de desechos s&oacute;lidos hospitalarios y principios de t&eacute;cnica&nbsp;as&eacute;ptica m&eacute;dica y quir&uacute;rgica</em>, proporciona al estudiante los conocimientos m&aacute;s&nbsp;elementales para poder realizar un adecuado manejo y descarte de los DSH, as&iacute; como&nbsp;tambi&eacute;n se brindan los principios y procedimientos de t&eacute;cnica as&eacute;ptica tanto m&eacute;dica como&nbsp;quir&uacute;rgica con el fin de disminuir la cadena de infecci&oacute;n.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">4 semanas con una duraci&oacute;n de 2 horas y media de clase por semana sincr&oacute;nica, y &nbsp;2 horas y media de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Brindar los conceptos b&aacute;sicos,&nbsp;clasificaci&oacute;n, tipos, simbolog&iacute;a, normativa&nbsp;legal aplicable de los desechos s&oacute;lidos&nbsp;hospitalarios para conocer el adecuado&nbsp;tratamiento de estos.</li>\r\n<li>Identificar los peligros y riesgos&nbsp;asociados al manejo inadecuado de los&nbsp;DSH para evitar incurrir en pr&aacute;cticas&nbsp;incorrectas en el futuro ejercicio profesional.</li>\r\n<li>Practicar la t&eacute;cnica as&eacute;ptica, m&eacute;dica y&nbsp;quir&uacute;rgica.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">4 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para aplicar la Gesti&oacute;n y manejo de desechos s&oacute;lidos hospitalarios y principios de t&eacute;cnica as&eacute;ptica m&eacute;dica y quir&uacute;rgica.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ab48e738ec42.55699406-Gestión y manejo de desechos sólidos hospitalarios y principios de técnica aséptica médica y quirúrgica.png', '2026-03-06 21:36:39', 6, 0, '', '', '', 0),
(87, 17, 'Curso de Modelado Arquitectónico con Revit', 'Formar al estudiante en el uso profesional de Autodesk Revit para el modelado arquitectónico', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p>Formar al estudiante en el uso profesional&nbsp;de Autodesk Revit para el modelado&nbsp;arquitect&oacute;nico en entorno BIM,&nbsp;desarrollando habilidades para crear,&nbsp;documentar y presentar proyectos&nbsp;arquitect&oacute;nicos en 2D y 3D de manera&nbsp;eficiente y estandarizada.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">16 semanas con una duraci&oacute;n de 3 horas de clase por semana sincr&oacute;nica, y &nbsp;3 horas de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ol>\r\n<li>Dominio pr&aacute;ctico de las principales&nbsp;herramientas de Autodesk Revit aplicadas&nbsp;al modelado arquitect&oacute;nico.</li>\r\n<li>Capacidad de desarrollar un proyecto&nbsp;arquitect&oacute;nico b&aacute;sico completo, desde la&nbsp;creaci&oacute;n del modelo 3D hasta la&nbsp;presentaci&oacute;n en planos arquitect&oacute;nicos&nbsp;b&aacute;sicos y recorridos virtuales.</li>\r\n<li>Certificaci&oacute;n de participaci&oacute;n (o de&nbsp;competencia, seg&uacute;n decidan ustedes)&nbsp;avalando su capacitaci&oacute;n en modelado 3D&nbsp;arquitect&oacute;nico con Revit.</li>\r\n<li>Un portafolio inicial compuesto por su&nbsp;proyecto final, &uacute;til para aplicar a empleos o&nbsp;trabajos freelance.</li>\r\n<li>Comprender los fundamentos de Revit y la&nbsp;metodolog&iacute;a BIM, aplic&aacute;ndolos en la creaci&oacute;n de&nbsp;modelos arquitect&oacute;nicos organizados y precisos.</li>\r\n<li>Desarrollar habilidades en la construcci&oacute;n de&nbsp;elementos arquitect&oacute;nicos b&aacute;sicos,&nbsp;documentaci&oacute;n gr&aacute;fica y control de la informaci&oacute;n&nbsp;del proyecto.</li>\r\n<li>Elaborar presentaciones profesionales&nbsp;mediante vistas 3D, renderizados b&aacute;sicos y&nbsp;recorridos virtuales, integrando el uso de&nbsp;herramientas de exportaci&oacute;n y compatibilidad con&nbsp;otros programas.</li>\r\n</ol>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">6 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar manejar el programa de Revit</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">Se recomienda tener una computadora con los&nbsp;siguientes requisitos para un buen desempe&ntilde;o en&nbsp;este curso:\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Procesador (CPU): Intel Core i7 o i9 de 10&ordf;&nbsp;generaci&oacute;n en adelante, o AMD Ryzen 7 o Ryzen&nbsp;9.</li>\r\n<li dir=\"ltr\" aria-level=\"1\">Memoria RAM: M&iacute;nimo 16 GB (idealmente&nbsp;32 GB si se quiere hacer renderizado m&aacute;s fluido).</li>\r\n<li dir=\"ltr\" aria-level=\"1\">Tarjeta Gr&aacute;fica (GPU): NVIDIA GeForce RTX&nbsp;3050, 3060 o superior, o su equivalente en AMD&nbsp;(RX 6600 o superior). Importante que tenga al&nbsp;menos 4 GB de VRAM (idealmente 6 u 8 GB para&nbsp;3D).</li>\r\n<li dir=\"ltr\" aria-level=\"1\">Almacenamiento: Disco de estado s&oacute;lido&nbsp;(SSD) de al menos 512 GB. (No recomendado&nbsp;trabajar con disco duro tradicional (HDD) porque&nbsp;ralentiza el software.)</li>\r\n<li dir=\"ltr\" aria-level=\"1\">Sistema Operativo: Windows 10 o 11 de 64&nbsp;bits.</li>\r\n<li dir=\"ltr\" aria-level=\"1\">Pantalla: Full HD (1920x1080) como m&iacute;nimo.&nbsp;Ideal de 15.6\" o m&aacute;s, especialmente si es laptop.</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ab4ab7244a01.89515884-Revit.png', '2026-03-06 21:44:23', 6, 0, '', '', '', 0),
(88, 19, 'Empleabilidad y Crecimiento Profesional', 'El taller Empleabilidad y Crecimiento Profesional está diseñado para fortalecer las competencias estratégicas que permiten a los estudiantes insertarse con éxito en el mercado laboral y proyectar un crecimiento profesional sostenible.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">Desarrollar en los&nbsp;participantes competencias&nbsp;estrat&eacute;gicas que fortalezcan&nbsp;su empleabilidad, optimicen&nbsp;su perfil profesional y les&nbsp;permitan planificar de manera&nbsp;estructurada su crecimiento&nbsp;laboral en el corto, mediano y&nbsp;largo plazo.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">1 sesi&oacute;n con una duraci&oacute;n de 4 horas sincr&oacute;nicas.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Identificar y fortalecer las habilidades t&eacute;cnicas y&nbsp;blandas del participante para definir una propuesta de&nbsp;valor profesional diferenciadora.</li>\r\n<li>Dise&ntilde;ar herramientas efectivas de empleabilidad,&nbsp;incluyendo curriculum vitae, perfil profesional digital y&nbsp;preparaci&oacute;n para entrevistas laborales.</li>\r\n<li>Elaborar un plan de crecimiento profesional&nbsp;estructurado, estableciendo metas claras y acciones&nbsp;concretas que favorezcan.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Temas</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Autoconocimiento y Marca Personal</li>\r\n<li dir=\"ltr\" role=\"presentation\">Curriculum Vital Estrat&eacute;gico y Perfil Profesional</li>\r\n<li dir=\"ltr\" role=\"presentation\">Entrevista Laboral y Comunicaci&oacute;n&nbsp;Profesional</li>\r\n<li dir=\"ltr\" role=\"presentation\">Plan de Crecimiento Profesional</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li><strong>Virtual</strong>, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder al taller</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">Computadora.</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ab592603f2d3.72124814-Empleabilidad y Crecimiento Profesional.png', '2026-03-06 22:45:58', 6, 0, '', '', '', 0),
(89, 18, 'Programa Especializado en Fitosanitario del Agro', 'Desarrolla en el estudiante las competencias necesarias para la identificación, selección y aplicación  técnica de manejo fitosanitario, garantizando el manejo integrado de plagas, enfermedades y malezas, y optimizando la nutrición vegetal bajo criterios de sostenibilidad y seguridad agroambiental y agroalimentario.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">El Programa de Fitosanitarios del Agro tiene como prop&oacute;sito fortalecer las competencias t&eacute;cnicas de los participantes en el manejo integrado fitosanitario, enfermedades y malezas, as&iacute; como en la nutrici&oacute;n vegetal.<br>Se abordar&aacute;n los principios, clasificaci&oacute;n, formulaci&oacute;n, aplicaci&oacute;n y manejo seguro de productos fitosanitarios utilizados en la agricultura moderna, promoviendo pr&aacute;cticas sostenibles, seguras y eficientes.<br>El programa combina teor&iacute;a y pr&aacute;ctica aplicada al contexto agr&iacute;cola nacional, considerando los aspectos t&eacute;cnicos, normativos y ambientales relacionados con el uso responsable de fitosanitarios.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del programa.</h2>\r\n<p dir=\"ltr\">4 meses.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Identificar los principales agentes fitopat&oacute;genos, plagas y malezas que afectan los cultivos agr&iacute;colas, comprendiendo su&nbsp; biolog&iacute;a y ciclo de vida.</li>\r\n<li>Analizar los tipos de formulaciones de plaguicidas y modos de acci&oacute;n de los productos del mercado y su correcta aplicaci&oacute;n en<br>diferentes sistemas productivos.</li>\r\n<li>Implementar estrategias de manejo integrado que combinen control qu&iacute;mico, biol&oacute;gico y cultural, priorizando la inocuidad<br>alimentaria y la sostenibilidad ambiental.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Perfil profesional&nbsp;</h2>\r\n<p>El egresado ser&aacute; capaz de identificar, diagnosticar y controlar los principales problemas fitosanitarios en sistemas agr&iacute;colas, aplicando productos y estrategias de manejo de forma t&eacute;cnica, responsable y sostenible. Estar&aacute; preparado para asesorar en la toma de&nbsp; decisiones fitosanitarias, implementar programas de manejo integrado y promover la sostenibilidad productiva en el sector agropecuario.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte profesional como fitosanitario del agro.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial y/o virtual.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones y plataformas de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li>Virtual, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>\r\n<p>&nbsp;</p>', 'post_69ac7af2be3998.52945621-Fitosanitario del Agro.png', '2026-03-06 22:55:11', 7, 0, '', '', '', 0),
(90, 18, 'Técnico Especializado en Registros Médicos', 'Forma técnicos en registros médicos capaces de gestionar de manera eficiente, ética y confidencial la información clínica y administrativa en los servicios de salud, aplicando principios técnicos, legales y tecnológicos que contribuyan a la calidad, seguridad y continuidad de la atención al paciente.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">Programa de formaci&oacute;n t&eacute;cnica orientado al desarrollo de competencias te&oacute;ricas y pr&aacute;cticas para la gesti&oacute;n, organizaci&oacute;n, resguardo y an&aacute;lisis de la informaci&oacute;n cl&iacute;nica y administrativa en los servicios de salud. El programa prepara al estudiantado para desempe&ntilde;arse de manera &eacute;tica, responsable y eficiente en el manejo del expediente cl&iacute;nico f&iacute;sico y digital, garantizando la confidencialidad, calidad y continuidad de la atenci&oacute;n sanitaria.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">12 meses con una duraci&oacute;n de 3 horas de clase por semana sincr&oacute;nica, y&nbsp; 3 horas de trabajo / estudio en casa por semana asincr&oacute;nica.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Analizar la estructura y funcionamiento del sector salud costarricense y su relaci&oacute;n con la gesti&oacute;n de los registros m&eacute;dicos.</li>\r\n<li>Aplicar terminolog&iacute;a m&eacute;dica y conocimientos b&aacute;sicos de anatom&iacute;a y fisiolog&iacute;a para la correcta&nbsp;interpretaci&oacute;n y registro de la informaci&oacute;n cl&iacute;nica.</li>\r\n<li>Gestionar el expediente cl&iacute;nico f&iacute;sico y digital conforme a la normativa legal, principios &eacute;ticos y est&aacute;ndares de confidencialidad vigentes.</li>\r\n<li>Utilizar sistemas de informaci&oacute;n, herramientas tecnol&oacute;gicas y datos estad&iacute;sticos b&aacute;sicos para apoyar los procesos&nbsp; administrativos y la toma de decisiones en los servicios de salud.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">48 lecciones organizadas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades para dar soporte como T&eacute;cnico Especializado en Registros M&eacute;dicos.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial y/o virtual.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones y plataformas de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li>Virtual, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ac7aad60bd39.49172525-Registros Médicos.png', '2026-03-06 23:02:37', 7, 0, '', '', '', 0),
(91, 19, 'Sabor a Fuego-El arte de la parrilla y platos especiales', 'Manejo de la parrilla, desde la selección y corte de carnes hasta su cocción y presentación de los platos,', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p dir=\"ltr\">Capacitar a los participantes en el manejo integral de la parrilla, desde la selecci&oacute;n y corte&nbsp;de carnes hasta su cocci&oacute;n y presentaci&oacute;n de los platos, incluyendo la preparaci&oacute;n de salsas&nbsp;y guarniciones, con el fin de ofrecer una experiencia gastron&oacute;mica completa y profesional.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">1 sesi&oacute;n con una duraci&oacute;n de 6 horas sincr&oacute;nicas.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Conocimientos a adquirir&nbsp;</h2>\r\n<ul>\r\n<li>Conocimiento sobre los diferentes&nbsp;cortes de carne y sus caracter&iacute;sticas.</li>\r\n<li>Dominio de t&eacute;cnicas de corte,&nbsp;cocci&oacute;n y presentaci&oacute;n de carnes a la&nbsp;parrilla.</li>\r\n<li>Habilidad para preparar salsas y&nbsp;guarniciones que complementen los&nbsp;platillos.</li>\r\n<li>Capacidad para armar men&uacute;s para&nbsp;eventos gastron&oacute;micos de acuerdo al&nbsp;curso.</li>\r\n<li>Presentaci&oacute;n de los diferentes&nbsp;platos culminados.</li>\r\n<li>Comprensi&oacute;n de la historia de la&nbsp;parrilla en diversas culturas.</li>\r\n<li>Experiencia pr&aacute;ctica en la cocci&oacute;n&nbsp;de carnes</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Temas</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Historia y Fundamentos de la Parrilla</li>\r\n<li dir=\"ltr\" role=\"presentation\">T&eacute;cnicas de Corte y Preparaci&oacute;n de Carnes</li>\r\n<li dir=\"ltr\" role=\"presentation\">Salsas y Guarniciones preparaci&oacute;n de platos</li>\r\n<li dir=\"ltr\" role=\"presentation\">Practica de cocci&oacute;n de sabor y fuego</li>\r\n<li dir=\"ltr\" role=\"presentation\">Degustaci&oacute;n de todos los platos efectuados en el curso</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Cada estudiante debe presentarse con:</strong>\r\n<ul>\r\n<li>Parrilla port&aacute;til (carb&oacute;n o gas) en buen estado&nbsp;de funcionamiento esta puede ser peque&ntilde;a o&nbsp;grande.</li>\r\n<li>Carb&oacute;n o gas seg&uacute;n el tipo de parrilla.</li>\r\n<li>Herramientas b&aacute;sicas de parrillero: pinzas,&nbsp;esp&aacute;tula, cuchillo de chef y tabla de picar.</li>\r\n<li>Cuaderno y bol&iacute;grafo para anotaciones.</li>\r\n<li>Recipientes para llevar muestras de las&nbsp;preparaciones.</li>\r\n<li>Un sart&eacute;n para las salsas.</li>\r\n<li>Mesa port&aacute;til para el asado.</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p>&nbsp;</p>', 'post_69ab5f4062f5b6.29118715-Sabor a Fuego.png', '2026-03-06 23:06:21', 6, 0, '', '', '', 0),
(92, 17, 'Profundización en Inseminación Artificial Bovina', 'Proporciona a los participantes los conocimientos teóricos y prácticos necesarios para llevar a cabo el proceso de inseminación artificial en bovinos de manera efectiva y segura.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p>El curso de inseminaci&oacute;n artificial bovina para principiantes es una capacitaci&oacute;n te&oacute;rico-pr&aacute;ctica dise&ntilde;ada para brindar a los participantes los conocimientos fundamentales necesarios para llevar a cabo la inseminaci&oacute;n artificial en el ganado bovino de manera adecuada. Durante el curso, se abordan temas como la anatom&iacute;a y fisiolog&iacute;a reproductiva de los bovinos, el ciclo estral, la<br>detecci&oacute;n del celo y la sincronizaci&oacute;n de los animales.</p>\r\n<p>Los participantes aprenden sobre el manejo correcto del material e instrumentos utilizados en la inseminaci&oacute;n artificial. Adem&aacute;s, se les instruye sobre las t&eacute;cnicas de recolecci&oacute;n, evaluaci&oacute;n y almacenamiento del semen, as&iacute; como la aplicaci&oacute;n adecuada de la t&eacute;cnica de inseminaci&oacute;n en las vacas. El programa tambi&eacute;n aborda aspectos de bioseguridad y manejo &eacute;tico, enfatizando la importancia del bienestar animal y la prevenci&oacute;n de enfermedades.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">3 meses.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Perfil de salida.&nbsp;</h2>\r\n<ul>\r\n<li>Un estudiante que ha completado con &eacute;xito un curso de inseminaci&oacute;n artificial bovina tiene la capacidad de llevar a cabo de manera efectiva y segura el proceso de inseminaci&oacute;n artificial en el ganado bovino. Adem&aacute;s, podr&aacute; adquirir habilidades pr&aacute;cticas en el manejo de material e instrumentos, como el correcto manejo del semen y la aplicaci&oacute;n de la t&eacute;cnica de inseminaci&oacute;n artificial en vacas, siguiendo los procedimientos adecuados.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades en Inseminaci&oacute;n Artificial Bovina.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ac78724ae7f8.31465263-Inseminación.png', '2026-03-06 23:41:08', 7, 0, '', '', '', 0),
(93, 17, 'Phonetic Kids - Nivel 1 - Edades de 7 a 12 años', 'Tiene como objetivo brindar al estudiante todas las herramientas y conocimientos necesarios para crear una base y desarrollo correcto del lenguaje del idioma inglés.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p>El programa tiene como objetivo brindar al estudiante todas las herramientas y conocimientos&nbsp;necesarios para crear una base y desarrollo correcto del lenguaje del idioma ingl&eacute;s.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">6 meses.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Perfil de salida.&nbsp;</h2>\r\n<ul>\r\n<li>Realizar comparaciones.</li>\r\n<li>Describir a personas.</li>\r\n<li>Hablar de rutinas diarias y su frecuencia.</li>\r\n<li>Expresar secuencia de acciones y rutinas diarias.</li>\r\n<li>Expresar opini&oacute;n y sentimientos.</li>\r\n<li>Describir personas en relacion con lo que est&aacute;n haciendo.</li>\r\n<li>Describir deportes y otras actividades.</li>\r\n<li>Describir lugares.</li>\r\n<li>Hablar sobre los deportes que pueden.</li>\r\n<li>Aprender a practicar y quieren hacer.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Recursos pr&aacute;cticos para aprender competencias y habilidades en el idioma ingl&eacute;s.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Cambridge: </strong>Plataforma y libro digital cambridge dise&ntilde;ado para efectuar progresos e interacciones evaluativos.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ac80de238378.68811840-Phonetic Kids.png', '2026-03-07 17:31:57', 7, 0, '', '', '', 0),
(94, 17, 'Tutorías Preparatorias para la prueba TOEIC.', 'El programa facilita a los discentes las herramientas necesarias para un adecuado desempeño en la prueba TOEIC.', '<h2 dir=\"ltr\">Descripci&oacute;n&nbsp;</h2>\r\n<p>El curso de Tutor&iacute;as Preparatorias para la Prueba TOEIC (Test of English for International Communication&trade;) impartido por el Centro de Ense&ntilde;anza y Formaci&oacute;n Integral (CEFI) consta de un &uacute;nico m&oacute;dulo con una duraci&oacute;n de 6 semanas, dirigido a Docentes en el &aacute;rea de Ingl&eacute;s de todas las modalidades, as&iacute; como a estudiantes de la carrera de Ense&ntilde;anza del Ingl&eacute;s que desean aprender t&eacute;cnicas eficaces para un mejor desempe&ntilde;o en la Prueba TOEIC para Direcci&oacute;n General de Servicio Civil.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del Curso</h2>\r\n<p dir=\"ltr\">8 semanas.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Lo que obtendr&aacute;s.&nbsp;</h2>\r\n<ul>\r\n<li>Analizar los &iacute;tems de evaluaci&oacute;n presentados en la prueba TOEIC.&nbsp;</li>\r\n<li>Aplicar t&eacute;cnicas que faciliten la comprensi&oacute;n y uso del vocabulario t&eacute;cnico en lectura, escritura y expresi&oacute;n oral.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones de primer nivel.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Modalidad</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\"><strong>Presencial</strong>, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li><strong>Virtual</strong>, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Plataformas&nbsp;</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ac80be457b31.50834431-TOEIC.png', '2026-03-07 17:55:58', 7, 0, '', '', '', 0);
INSERT INTO `posts` (`id_post`, `id_category`, `title`, `synopsis`, `content`, `main_image`, `created_at`, `id_user`, `orden`, `instructor_name`, `instructor_title`, `instructor_photo`, `show_in_instructors`) VALUES
(95, 17, 'Creación de Páginas Web de 0 a 100 con WordPress', 'Proporciona al estudiante los conocimientos y habilidades necesarios para diseñar, desarrollar y gestionar sitios web de manera efectiva utilizando esta plataforma popular y versátil.', '<h2 dir=\"ltr\">Descripci&oacute;n.</h2>\r\n<p>Proporcionar&aacute; al estudiante los conocimientos y habilidades necesarios para dise&ntilde;ar, desarrollar y gestionar sitios web de manera efectiva utilizando esta plataforma popular y vers&aacute;til.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del programa.</h2>\r\n<p>4 meses.</p>\r\n<hr>\r\n<h2 dir=\"ltr\">Perfil profesional.</h2>\r\n<p dir=\"ltr\">Los graduados del curso de WordPress de 4 meses habr&aacute;n adquirido habilidades t&eacute;cnicas y conocimientos fundmentales en el uso avanzado de la plataforma WordPress. Estar&aacute;n preparados para dise&ntilde;ar, desarrollar y gestionar sitios web de manera eficiente y efectiva. El perfil de salida destaca las competencias y logros alcanzados por los participantes al completar el programa:</p>\r\n<ul>\r\n<li dir=\"ltr\">Instalaci&oacute;n y configuraci&oacute;n de WordPress.</li>\r\n<li dir=\"ltr\">Administraci&oacute;n efectiva del panel de control y ajustes del sitio.</li>\r\n<li dir=\"ltr\">Desarrollo de entradas y p&aacute;ginas atractivas.</li>\r\n<li dir=\"ltr\">Utilizaci&oacute;n de categor&iacute;as y etiquetas par organizar contenido.</li>\r\n<li dir=\"ltr\">Integraci&oacute;n de multimedia para enriquecer la experiencia del usuario.</li>\r\n<li dir=\"ltr\">Selecci&oacute;n e instalaci&oacute;n de temas adecuados.</li>\r\n<li dir=\"ltr\">Personalizaci&oacute;n avanzada de temas y uso de widgets.</li>\r\n<li dir=\"ltr\">Creaci&oacute;n de men&uacute;s y navegaci&oacute;n intuitiva.</li>\r\n<li dir=\"ltr\">Conocimiento y aplicaci&oacute;n de plugins para ampliar la funcionalidd del sitio.</li>\r\n<li dir=\"ltr\">Configuraci&oacute;n y personalizaci&oacute;n de plugins populares.</li>\r\n<li dir=\"ltr\">Implementaci&oacute;n de estrategias de seguridad.</li>\r\n<li dir=\"ltr\">Optimizaci&oacute;n del rendimiento del sitio.</li>\r\n<li dir=\"ltr\">Respaldo y restauraci&oacute;n del sitio de manera efectiva.</li>\r\n<li dir=\"ltr\">Integraci&oacute;n de herramientas de an&aacute;lisis para evaluar el rendimiento del sitio.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios.</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso a nuestras plataformas profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial y/o virtual.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones y plataformas de primer nivel.&nbsp;\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Modalidad.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n<li>Virtual, mediante transmisi&oacute;n en vivo v&iacute;a Zoom. Plataforma CEFI Virtual como medio de recursos asincr&oacute;nicos.\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Plataformas.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\"><strong>CEFI Virtual:&nbsp;</strong>La plataforma CEFI Virtual es un sistema de ense&ntilde;anza dise&ntilde;ado para crear y gestionar espacios de aprendizaje online adaptados a las necesidades de profesores, estudiantes y administradores. Puedes mantener una interacci&oacute;n bastante activa en el desarrollo del programa.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Requisitos.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Contar con un dispositivo inteligente y conexi&oacute;n a internet.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">&nbsp;</p>\r\n<p dir=\"ltr\">Contar con computadora.</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<h2 dir=\"ltr\">&nbsp;</h2>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivo inteligente para acceder a la plataforma CEFI Virtual.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n</ul>', 'post_69ac8082ea3a38.62763615-Creación de Páginas Web de 0 a 100 con WordPress.png', '2026-03-07 18:41:29', 7, 0, '', '', '', 0),
(96, 17, 'Globos Creativos Nivel I', 'Desarrolla habilidades de diseño temático: Capacitar a los participantes para identificar, desarrollar y aplicar temáticas creativas y apropiadas para fiestas de verano familiares, considerando las preferencias y\r\nnecesidades específicas de los clientes.', '<h2 dir=\"ltr\">Descripci&oacute;n.</h2>\r\n<p>Capacita a los participantes en el dise&ntilde;o y la decoraci&oacute;n de fiestas de verano y eventos familiares desde la perspectiva de un decorador profesional, proporcion&aacute;ndoles los conocimientos y habilidades necesarios para planificar, organizar y ejecutar con &eacute;xito<br>celebraciones memorables y personalizadas.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<h2 dir=\"ltr\">Duraci&oacute;n del programa.</h2>\r\n<p>8 semanas.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Perfil profesional.</h2>\r\n<ul>\r\n<li>\r\n<p dir=\"ltr\">Capacidad para conceptualizar, dise&ntilde;ar y ejecutar decoraciones tem&aacute;ticas utilizando globos de manera creativa y est&eacute;ticamente atractiva para eventos familiares y corporativos.</p>\r\n</li>\r\n<li>Habilidad para manipular y construir diferentes formas, figuras, arcos, columnas y esculturas con globos, integrando t&eacute;cnicas avanzadas para lograr dise&ntilde;os complejos.</li>\r\n<li>Aptitud para planificar y organizar eventos familiares de verano, considerando la decoraci&oacute;n con globos como elemento esencial, gestionando recursos, tiempo y presupuesto de manera efectiva.</li>\r\n<li>Destreza para desarrollar conceptos tem&aacute;ticos innovadores y adaptar dise&ntilde;os de decoraci&oacute;n con globos a las preferencias y&nbsp;necesidades espec&iacute;ficas de los clientes para eventos familiares y corporativos.</li>\r\n<li>Conocimiento de aspectos profesionales y &eacute;ticos relacionados con la industria de la decoraci&oacute;n de eventos, incluyendo la gesti&oacute;n de clientes, la comunicaci&oacute;n efectiva y la conducta profesional.</li>\r\n<li>Competencia para presentar y exhibir proyectos de decoraci&oacute;n con globos de manera profesional, demostrando habilidades de evaluaci&oacute;n y autocr&iacute;tica.</li>\r\n</ul>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<h2 dir=\"ltr\">Beneficios.</h2>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Proyectos guiados paso a paso con resultados profesionales.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Aprende en la modalidad presencial y/o virtual.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicaciones din&aacute;micas, claras y objetivas.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Soporte t&eacute;cnico personalizado.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Relaci&oacute;n directa con personal docente y administrativo.&nbsp;</li>\r\n<li dir=\"ltr\" role=\"presentation\">Acceso al instructor para resolver dudas.</li>\r\n<li>Beneficios en diferentes comercios gracias a nuestros convenios.</li>\r\n<li>Instalaciones y plataformas de primer nivel.&nbsp;\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">Modalidad.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">Presencial, en nuestra sede del Caribe en el Centro Educativo Valle del Sol.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<hr>\r\n<p dir=\"ltr\" role=\"presentation\">&nbsp;</p>\r\n<h2 dir=\"ltr\">Requisitos.</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Leer y aceptar las pol&iacute;ticas institucionales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Completar el proceso de matr&iacute;cula.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Fotograf&iacute;a de la c&eacute;dula de identidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Efectuar el pago que corresponda.</p>\r\n<p dir=\"ltr\" role=\"presentation\">&nbsp;</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<hr>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n</li>\r\n</ul>\r\n<h2 dir=\"ltr\">&iquest;Qu&eacute; se necesita?</h2>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Deseo de superaci&oacute;n.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">El estudiante debe llevar sus propios materiales.</li>\r\n</ul>', 'post_69ac7fe7de4fe6.06764146-Globos.png', '2026-03-07 19:04:59', 7, 0, '', '', '', 0);

